INSERT OR REPLACE INTO contents (id, type, l1, l2, l3_label, title, lead_text, body_text, l1_en, l2_en, l3_label_en, title_en, lead_text_en, body_text_en, l1_tw, l2_tw, l3_label_tw, title_tw, lead_text_tw, body_text_tw, image1, image2, image3, image4, image5, image6, homepage, related1_url, related1_title, related2_url, related2_title, ec_site, sns_instagram, sns_facebook, sns_x, sns_line, sns_tiktok, address, contact_form_url, contact_email, contact_phone, remarks, download_url, business_days, business_start, business_end, closed_days, business_remarks, start_date, end_date, start_time, end_time, fee, belongings, target_audience, organizer_name, organizer_contact, application_method, venue_remarks) VALUES
('02-02-00-0001', 'sheet_import', '知る', '飯綱町について', NULL, '地理とアクセス', '里山の風景が残りつつ、都市からのアクセスも良好な「ちょうどいい田舎」。', '長野県北部に位置する飯綱町は、標高500〜900mの丘陵地帯に広がる、人口およそ１万人の小さな町です。北信五岳を望む古き良き里山の風景が魅力で、昼夜の寒暖差に恵まれた気候はりんご栽培に適しており、豊かな自然と暮らしやすさを両立しています。隣接する長野市や中野市へは車で20〜30分と通勤圏内で、生活利便性も確保されています。東京からは新幹線と在来線で約2時間、大阪からも約4時間でアクセス可能。「ちょうどいい田舎」として、多くの人々を惹きつけています。', 'Discover', 'Our Heritage', NULL, 'Geography and Access', 'An Ideal Countryside where traditional satoyama landscapes endure, yet offers excellent access to urban centers.', 'Iizuna Town, located in northern Nagano Prefecture, is a small town with a population of approximately 10,000, spread across hilly terrain at an elevation of 500 to 900 meters. Its charm lies in the timeless satoyama landscapes overlooking the Hokushin Five Mountains. The climate, blessed with significant diurnal temperature variation, is ideal for agriculture, balancing abundant nature with high livability. Neighboring Nagano City and Nakano City are within a 20-30 minute drive, ensuring convenience for daily life and commuting. Access from Tokyo is approximately 2 hours by Shinkansen and local train lines, and about 4 hours from Osaka. As an Ideal Countryside, it attracts many people.', '探索', '關於飯綱町', NULL, '地理與交通', '保留里山風光，同時擁有便利都市交通的「恰到好處的鄉村」。', '飯綱町位於長野縣北部，是一座人口約一萬人，座落於海拔500至900公尺丘陵地帶的小鎮。這裡的魅力在於能眺望北信五嶽的古樸里山風光，晝夜溫差大的氣候非常適合農業發展，完美結合了豐饒自然與宜居生活。開車20至30分鐘即可抵達鄰近的長野市與中野市，屬於通勤圈範圍內，生活便利性無虞。從東京搭乘新幹線與在地鐵路約2小時可達，從大阪出發也約4小時即可抵達。作為「恰到好處的鄉村」，吸引了眾多人們前來。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/a6835820-8ee6-013e-065c-0a58a9feac02/iizuna_location.png', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/866.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-02-00-0002', 'sheet_import', '知る', '飯綱町について', NULL, 'これまでの歩み', '伝統と挑戦が息づくりんごのまち。', '飯綱町は2005年に、旧牟礼村と旧三水村が合併して誕生しました。町の基幹産業の一つであるりんご栽培は、明治時代にはじまり、大正期の農業団体設立や昭和初期の桑畑転換を経て発展。昭和40年代には旧三水村が全国有数の生産地として「日本一のりんご村」と呼ばれました。現在も町内各地でりんご栽培が続けられており、海外品種を含めた50以上の多種多様なりんごが栽培されています。また、北国街道の宿場「牟礼宿」として栄えた歴史や、郷土料理「やたら」をはじめとする暮らしに根付いた伝統文化を守りながら、閉校した小学校を活用して、複合施設「いいづなコネクトWEST」「いいづなコネクトEAST」を開設するなど、新しいことにも挑戦し続けている町です。', 'Discover', 'Our Heritage', NULL, 'Our Journey So Far', 'An apple town where tradition and innovation thrive.', 'Iizuna Town was formed in 2005 through the merger of the former Mure Village and former Samizu Village. Apple cultivation, one of the town''s core industries, began in the Meiji era and developed through the establishment of agricultural organizations in the Taisho period and the conversion of mulberry fields in the early Showa period. In the Showa 40s (1960s), the former Samizu Village was renowned as Japan''s premier apple-producing village. Today, apple cultivation continues throughout the town, with over 50 diverse varieties, including foreign varieties, being grown. While preserving its rich history as Mure-juku, a Post Town on the Hokkoku Kaido, and traditional cultures rooted in daily life, such as the Local Cuisine Yatara, the town also continues to embrace new challenges. This includes the establishment of the multi-purpose complexes Iizuna Connect WEST and Iizuna Connect EAST, utilizing former elementary school buildings.', '探索', '關於飯綱町', NULL, '歷史沿革', '傳統與創新並存的蘋果小镇。', '飯綱町於2005年由舊牟禮村與舊三水村合併而成。蘋果栽培是本町的基幹產業之一，始於明治時代，歷經大正時期農業團體的成立以及昭和初期桑田轉作，逐步發展。昭和40年代（1960年代），舊三水村曾以全國首屈一指的蘋果產地之姿，被譽為「日本第一的蘋果村」。如今，町內各地仍持續進行蘋果栽培，種植著包含海外品種在內，超過50種多樣化的蘋果。此外，本町在守護北國街道宿場「牟禮宿」的繁榮歷史，以及以在地特色料理Yatara為首，根植於生活的傳統文化的同時，也持續挑戰新事物，例如活用廢校小學，開設了複合設施「飯綱Connect WEST」與「飯綱Connect EAST」。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/c2823380-8eef-013e-f645-0a58a9feac02/top_logoContents_sp.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/865.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-02-00-0003', 'sheet_import', '知る', '飯綱町について', NULL, 'りんご栽培に適した気候条件', '昼夜の寒暖差と豊かな自然が、りんごの品質を高める。', '飯綱町は、標高と、内陸性気候特有の昼夜の寒暖差に恵まれ、りんご栽培に理想的な条件を備えています。日中に生成された糖分が夜間の低温で保持されることで甘みが凝縮し、実がしっかりと引き締まると言われています。加えて、糖度と酸度のバランスも抜群。澄んだ空気や豊富な水源、長い日照時間が、飯綱町ならではのりんごの美味しさを実現し、科学的にも証明されています。', 'Discover', 'Our Heritage', NULL, 'Climate Conditions Suitable for Apple Cultivation', 'Diurnal temperature variation and abundant nature enhance the quality of apples.', 'Iizuna Town is blessed with ideal conditions for apple cultivation, thanks to its elevation and the significant diurnal temperature variation characteristic of its Inland Climate. It is said that sugars produced during the day are retained by low night temperatures, concentrating the sweetness and firming the fruit. Furthermore, the balance of Sugar Content and Acidity is exceptional. Clear air, abundant water sources, and long hours of sunshine contribute to the unique deliciousness of Iizuna Town''s apples, which has also been scientifically substantiated.', '探索', '關於飯綱町', NULL, '適合蘋果栽培的氣候條件', '晝夜溫差與豐饒自然，提升蘋果品質。', '飯綱町擁有得天獨厚的海拔條件，以及內陸性氣候特有的晝夜溫差，具備了蘋果栽培的理想環境。據說，白天生成的糖分在夜間低溫下得以保留，使甜味濃縮，果實也更加緊實。此外，糖度與酸度的平衡也極為出色。清澈的空氣、豐沛的水源以及充足的日照時間，共同造就了飯綱町獨有的蘋果美味，這也已獲得科學驗證。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/f2837410-8f03-013e-e63d-0a58a9feac02/photo-intermediate.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://1127.info/about/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-02-00-0004', 'sheet_import', '知る', '飯綱町について', NULL, 'りんごを核に描く未来戦略', '「りんご」を核に、地域資源を磨き上げる独自のまちづくりを推進。', '飯綱町は、「日本一のりんごの町」を掲げ、りんごを核とした地域戦略「輝く農山村地域創造推進プロジェクト」を展開しています。抜群の糖度と酸度のバランスや食感の科学的証明を生かした高付加価値化、未利用資源の活用、そして観光や教育と結びつけた関係人口づくりなど、りんごを中心に多方面へ波及する取り組みが進行中です。農業だけに留まらず、健康・文化・働き方までを含めた持続可能な地域モデルをかたちづくり、「ちょうどいい田舎」から新たな未来を発信しています。', 'Discover', 'Our Heritage', NULL, 'Crafting a Future Strategy with Apples at its Core', 'Promoting unique town development that refines local resources, with apples as its central pillar.', 'Iizuna Town champions itself as ''Japan''s premier apple town,'' driving a regional strategy centered on apples, known as the ''Shining Agricultural and Mountain Village Creation Promotion Project.'' This initiative encompasses a wide range of efforts radiating from apples, including adding high value by leveraging the Scientific Substantiation of their excellent balance of sugar content and acidity, and unique Texture; utilizing untapped resources; and fostering a Relationship Population through tourism and education. Beyond agriculture, the town is shaping a Sustainable regional model that embraces health, culture, and diverse working styles, broadcasting a new future from its Ideal Countryside.', '探索', '關於飯綱町', NULL, '以蘋果為核心描繪的未來戰略', '以「蘋果」為核心，推動獨特的城鎮建設，精進地方資源。', '飯綱町以「日本首屈一指的蘋果小镇」為目標，推動以蘋果為核心的區域戰略「閃耀農山村地域創造推進計畫」。這項計畫以蘋果卓越的糖酸比與口感的科學驗證為基礎，致力於提升附加價值、活化未利用資源，並透過結合觀光與教育來創造「關係人口」，以蘋果為中心，多面向的措施正持續推展。這不僅限於農業，更涵蓋健康、文化、生活方式等層面，旨在建構永續的區域模式，從「恰到好處的鄉村」向世界發送嶄新的未來。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/3bb6c340-8d6a-013e-ae9b-0a58a9feac02/20231120_mitsudon-11.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/10947.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-03-00-0005', 'sheet_import', '知る', 'いいづなりんごの特徴', NULL, '多様な品種', '季節ごとに多彩な味が楽しめる、50種以上のりんごの宝庫。', '町内では「ふじ」「つがる」といった定番に加え、長野県生まれの「秋映」「シナノスイート」「シナノゴールド」「シナノリップ」など、さまざまな品種が栽培されています。希少な和りんごの「高坂りんご」や調理や加工に向く海外品種、さらには赤果肉りんごまで、その品種の数は50種以上。昼夜の寒暖差に恵まれた気候と豊かな水源が、多彩な味わいと高い品質を支えています。飯綱町のりんごシーズンは「ブラムリー」を皮切りに８月にスタートします。季節ごとに異なる味が楽しめるのも、多種多様なな品種を育むこの地域ならではの魅力です。', 'Discover', 'Flavor & Science', NULL, 'Diverse Varieties', 'A treasure trove of over 50 apple varieties, offering different tastes each season.', 'In Iizuna Town, in addition to classic varieties like Fuji Apple, Tsugaru, and Orin, a rich array of unique varieties developed in Nagano Prefecture, such as Akibae, Shinano Sweet, and Shinano Gold, are cultivated. The town boasts over 50 varieties, including the rare Native Japanese Apple ''Kosaka Apple'', foreign varieties suitable for Cooking Apple, and even Red-fleshed Apples. The climate, blessed with significant Diurnal Temperature Variation, and abundant water sources support this diverse range of flavors and high quality. The ability to enjoy different tastes each season is a unique charm of this region, which cultivates such a wide variety of apples.', '探索', '飯綱蘋果的特徵', NULL, '多樣的蘋果品種', '超過50種蘋果的寶庫，每個季節都能品嚐到不同風味。', '飯綱町內除了「富士蘋果 (Fuji)」、「津輕蘋果 (Tsugaru)」、「王林蘋果 (Orin)」等經典品種外，還栽培著長野縣原生的「秋映蘋果 (Akiho)」、「信濃甜蘋果 (Shinano Sweet)」、「信濃黃金蘋果 (Shinano Gold)」等獨具特色的品種。從稀有的日本原生蘋果「高坂蘋果 (Kosaka Apple)」，到適合料理的西洋蘋果品種，乃至於紅肉蘋果，其數量多達50種以上。得天獨厚的晝夜溫差氣候與豐沛的水源，支持著蘋果多樣的風味與高品質。每個季節都能品嚐到不同風味，正是這個孕育多樣品種的地區獨有的魅力。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/8ae3ad00-8d6a-013e-bcd3-0a58a9feac02/IMG_2898.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-03-00-0006', 'sheet_import', '知る', 'いいづなりんごの特徴', NULL, '高い栄養価', '食べるほどにうれしい、栄養と機能性が詰まった果実の魅力。', '「1日1個のりんごで医者いらず」（An apple a day keeps the doctor away／イギリス・ウェールズ地方に伝わることわざ）と言われるほど、りんごは食物繊維やカリウム、ビタミン類を豊富に含み、腸内環境を整えたり生活習慣病の予防に役立つ果物として知られています。特に希少な和りんごの「高坂りんご」は注目されており、老化を抑える抗酸化作用を持つプロシアニジンが「ふじ」の約10倍含まれることが研究で確認されています。さらに内臓脂肪減少効果も期待され、加工品開発にも繋がっています。そのほか赤果肉りんごに含まれるアントシアニンなど、品種ごとに機能性研究が進められています。', 'Discover', 'Flavor & Science', NULL, 'High Nutritional Value', 'The appeal of fruit packed with nutrition and Functional Benefits, a delight with every bite.', 'Apples are known as fruits rich in dietary fiber, potassium, and vitamins, helping to regulate the intestinal environment and prevent lifestyle-related diseases. The ancient variety from Iizuna Town, ''Kosaka Apple'', is particularly noteworthy; research has confirmed it contains approximately 10 times more Procyanidin, an Antioxidant Effect that suppresses aging, than the Fuji Apple. Furthermore, its potential for Visceral Fat reduction is also anticipated, leading to the development of processed products. Beyond this, Functional Benefits research is progressing for various varieties, such as the Anthocyanin found in Red-fleshed Apples.', '探索', '飯綱蘋果的特徵', NULL, '高營養價值', '富含營養與機能性保健功效的果實魅力，越吃越健康。', '蘋果富含膳食纖維、鉀、維生素等，是眾所周知有助於調理腸道環境、預防生活習慣病的果實。特別是飯綱町的古老品種「高坂蘋果 (Kosaka Apple)」備受矚目，研究證實其所含的「原花青素」，具有抑制老化的「抗氧化作用」，含量約為「富士蘋果 (Fuji)」的10倍。此外，它還被期待具有內臟脂肪減少的功效，並已應用於加工品的開發。除此之外，針對紅肉蘋果所含的「花青素」等，各類品種的機能性保健功效研究也正持續進行中。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/b4170770-8d6a-013e-bcf1-0a58a9feac02/sunfuji_mitsu-2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-03-00-0007', 'sheet_import', '知る', 'いいづなりんごの特徴', NULL, 'シャキシャキの食感', '歯ごたえの良さは数値でも証明', '飯綱町産のりんごの大きな魅力は、ひと口かじった瞬間に伝わる「シャキシャキ」とした歯ごたえです。この食感は、長野県工業技術総合センターによる測定で破断強度が高いことが示され、科学的にも証明されています。背景には、昼夜の寒暖差が大きい内陸性気候があり、これによって実がしっかりと引き締まり、特有の硬さが生まれます。また、栽培環境と品種特性が合わさることで独自の歯ごたえが育まれています。味とともにこの食感にもぜひご注目ください。', 'Discover', 'Flavor & Science', NULL, 'Crisp Texture', 'The excellent crunchiness of Iizuna apples is a scientifically proven characteristic.', 'A major appeal of Iizuna Town''s apples is the satisfying crispness that greets you with every bite. This texture is scientifically substantiated, with measurements by the Nagano Prefecture General Industrial Technology Center showing high fracture strength. This unique firmness is attributed to Iizuna''s inland climate, which features significant Diurnal Temperature Variation, causing the fruit to firm up beautifully. Depending on the variety, you can enjoy a refreshing crispness, as found in Shinano Lip and Shinano Red, where the cultivation environment and varietal characteristics combine to foster this distinctive texture.', '探索', '飯綱蘋果的特徵', NULL, '爽脆的口感', '絕佳咬勁經科學驗證，是飯綱蘋果的鮮明特色。', '飯綱町蘋果的巨大魅力，在於一口咬下瞬間感受到的「爽脆」咬勁。這種口感經長野縣工業技術綜合中心 (Nagano Prefecture General Industrial Technology Center) 測量顯示其斷裂強度高，亦獲得科學驗證。其背後原因在於晝夜溫差大的內陸性氣候，使果實緊實，產生獨特的硬度。部分品種如信濃麗 (Shinano Lip) 和信濃紅 (Shinano Red) 則能享受清爽的口感，栽培環境與品種特性相結合，共同孕育出獨特的咬勁。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/02d66ae0-8d6a-013e-0556-0a58a9feac02/20230118_apple_cut-3.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-03-00-0008', 'sheet_import', '知る', 'いいづなりんごの特徴', NULL, '甘みと酸味のバランス', '絶妙な糖酸バランスが生み出す飯綱町産りんごの深い味わい', 'りんごの美味しさを大きく左右するのが、甘みと酸味の調和です。長野県工業技術総合センターの調査では、飯綱町産の「ふじ」が、他産地のりんごに比べ、糖度・酸度ともに高い水準を記録し、さらには一般的に美味しいとされる糖酸比（甘味と酸味のバランス）30〜40に近い数値を示しました。甘さと酸っぱさが絶妙に重なり合うことで、豊かなコクと爽やかさが生まれ、多くの人に愛される味わいとなっています。', 'Discover', 'Flavor & Science', NULL, 'Balance of Sweetness and Acidity', 'An exquisite sugar-acid balance creates the deep, rich flavor of Iizuna apples.', 'The harmony of sweetness and acidity significantly influences an apple''s deliciousness. A study by the Nagano Prefecture General Industrial Technology Center revealed that Iizuna-grown Fuji Apples recorded high levels of both Sugar Content and acidity compared to apples from other regions. Furthermore, they exhibited a Sugar-Acid Ratio close to the generally preferred range of 30-40. This exquisite interplay of sweetness and tartness creates a rich depth of flavor and refreshing quality, making them beloved by many.', '探索', '飯綱蘋果的特徵', NULL, '甜度與酸度的完美平衡', '絕妙的糖酸比，造就蘋果深邃的風味。', '蘋果美味與否，甜度與酸度的和諧是關鍵。長野縣工業技術綜合中心 (Nagano Prefecture General Industrial Technology Center) 的調查顯示，飯綱町產的「富士蘋果 (Fuji)」相較於其他產地的蘋果，在糖度與酸度上均達到高水準。此外，其糖酸比（甜味與酸味的平衡）也接近一般公認美味的30至40之間。甜與酸的絕妙交織，創造出豐富的濃郁風味與清爽感，成為深受大眾喜愛的滋味。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/cd850820-8d6a-013e-c3bf-0a58a9feac02/%E3%83%95%E3%82%99%E3%83%A9%E3%83%A0%E3%83%AA%E3%83%BC_5.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-03-00-0009', 'sheet_import', '知る', 'いいづなりんごの特徴', NULL, '栽培方法の特徴', '圃場の条件にあわせた栽培手法でりんご生産を守る', '町内では大きく分けて「普通（丸葉【まるば】）栽培」と「わい化（わいか）栽培」という２つの栽培方法でりんごが生産されています。普通栽培は、根がしっかり張る大きくて樹を育てて、実をならせる伝統的な栽培方法で、病気や寒さに強いのが特長です。町内には樹齢3～40年を越える木が現役で頑張っている畑も少なくありません。「古い木のほうがおいしいりんごがとれる」という声もあるくらい。一方、わい化栽培は、1本1本の木をコンパクト仕立てて、1本の木により多くの実をならせる方法で、苗を植えてから出荷できるりんごが収穫できるようになるまでが普通栽培よりも格段に速く、作業もしやすくなります。飯綱町では畑ごとの条件や農家の工夫によって両方を組み合わせることで、味わいの良さと安定した収穫を両立させています。', 'Discover', 'Flavor & Science', NULL, 'Distinctive Cultivation Methods', 'Apple farmers employ innovative Tree Training methods to achieve both deliciousness and cultivation efficiency.', 'Apple orchards primarily utilize two cultivation methods: Standard Cultivation and Dwarfing Cultivation. Standard Cultivation involves traditional trees with deep, strong root systems that can be grown for many years, known for their resistance to disease and cold. Dwarfing Cultivation, on the other hand, involves training smaller trees planted at high density, allowing for earlier harvests and easier management. In Iizuna Town, farmers combine both methods, adapting to specific field conditions and employing their ingenuity to ensure both superior flavor and stable yields.', '探索', '飯綱蘋果的特徵', NULL, '栽培方法的特色', '蘋果農民巧妙運用樹型培育技術，兼顧美味與栽種便利性。', '蘋果園主要有兩種栽培方式：「丸葉 (Maruba)」和「矮化栽培 (Waika)」。丸葉 (Maruba) 是一種根系穩固、可長期培育的傳統樹型，特點是抗病耐寒。而矮化栽培 (Waika) 則是將樹木培育得較小，以高密度種植的方式，能提早收穫並方便作業。飯綱町的農民會根據各個果園的條件和自身經驗，將這兩種方法結合運用，以實現絕佳風味與穩定收成。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/0c9c9c80-8ef3-013e-1b1b-0a58a9feac02/__1.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-04-0001', 'sheet_import', '知る', '栽培されている品種', '町指定天然記念物', '高坂林檎', '幻の和りんご、小さな実が鈴なりに実る', '明治時代に西洋りんごが日本に伝わる以前に中国から伝来したとされる在来種。品種名は、産地だった飯綱町高坂（こうさか）の地名に由来。昭和末期に絶滅寸前となったが町内有志農家による保存活動で命脈をつなぎ、町内原木2本が町の天然記念物に指定されている。全国的にも在来種の現存はとても珍しい。味は渋くて、酸っぱいため、生食はできないが、近年、ポリフェノールの一種である「プロシアニジン」を豊富に含んでいることがわかり、ジュースやシードルへの加工用として注目されている。収穫は８月頃。', 'Discover', 'Apple Varieties', 'Heirloom & Monuments', 'Kosaka Apple', 'An elusive native Japanese apple, bearing small fruits in abundance.', 'This native variety is believed to have been introduced from China before the arrival of Western Apples. It was on the verge of extinction in the late Showa era, but preservation efforts kept it alive, and two original trees in the town have been designated as natural monuments. Recently, it has gained attention as an ingredient for Cider.', '探索', '蘋果品種', '天然紀念物品種', '高坂苹果', '夢幻般的日本原生蘋果，小巧果實纍纍', '據傳是在西洋蘋果傳入日本之前，從中國傳來的日本原生品種。在昭和末期曾瀕臨絕種，但透過保存活動得以延續命脈，町內有兩棵原木被指定為天然紀念物。近年來，作為蘋果酒 (Cider) 的原料而備受矚目。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E9%AB%98%E5%9D%82%E6%9E%97%E6%AA%8E.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-05-0022', 'sheet_import', '知る', '栽培されている品種', '定番品種', 'サンつがる', '9月上旬に出回る甘み豊かな早生種', '果汁が多く甘さが強いのが特徴。果肉は柔らかめで酸味は少なく食べやすい。早い時期に楽しめるため人気の高い品種です。', 'Discover', 'Apple Varieties', 'Classic Varieties', 'Sun Tsugaru', 'A richly sweet, early-ripening variety available in early September.', 'Known for its abundant juice and intense sweetness, the Sun Tsugaru apple features tender flesh with low acidity, making it exceptionally easy to enjoy. Its early availability makes it a highly popular choice among apple enthusiasts.', '探索', '蘋果品種', '經典品種', '太阳津轻', '9月上旬上市的甜美早生品種', '果汁豐富，甜度高是其特色。果肉柔軟，酸度較低，易於食用。由於上市時間早，是很受歡迎的品種。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B5%E3%83%B3%E3%81%A4%E3%81%8C%E3%82%8B.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-05-0023', 'sheet_import', '知る', '栽培されている品種', '定番品種', '紅玉', '強い酸味と多汁さで加工に最適', '10月中旬が旬。鮮やかな赤色と酸味の強さが特徴で、アップルパイなどお菓子用に根強い人気があります。', 'Discover', 'Apple Varieties', 'Classic Varieties', 'Jonathan', 'Ideal for processing, characterized by strong acidity and juiciness.', 'Peaking in mid-October, the Jonathan apple is distinguished by its vibrant red color and pronounced tartness. This makes it a long-standing favorite for baking, especially for delicious Apple Pies and other sweets.', '探索', '蘋果品種', '經典品種', '紅玉', '酸度強且多汁，最適合加工', '10月中旬為盛產期。鮮豔的紅色與強烈的酸度是其特色，作為蘋果派等甜點的原料，擁有居高不下的人氣。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E7%B4%85%E7%8E%89.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-05-0025', 'sheet_import', '知る', '栽培されている品種', '定番品種', '王林', '黄緑色の果皮と強い甘みが特徴', '酸味が少なく、芳醇な香りとパリッとした食感が楽しめる。保存性が高く冬まで美味しさを保ち、甘党に好まれるりんごです。', 'Discover', 'Apple Varieties', 'Classic Varieties', 'Orin', 'Features yellowish-green skin and intense sweetness.', 'The Orin apple offers a delightful combination of low acidity, a rich aroma, and a crisp texture. Renowned for its excellent shelf life, it retains its delicious flavor well into winter, making it a beloved choice for those with a sweet tooth.', '探索', '蘋果品種', '經典品種', '王林', '黃綠色果皮與濃郁甜味是其特色', '酸度較低，可享受其芳醇香氣與清脆口感。保存性高，能將美味維持至冬季，是嗜甜者喜愛的蘋果。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E7%8E%8B%E6%9E%97.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-05-0027', 'sheet_import', '知る', '栽培されている品種', '定番品種', 'サンふじ', '甘み・酸味・食感が揃った世界的人気品種', '日本を代表する品種で、11月中旬が旬。無袋栽培のサンふじは蜜入りで特に甘く、シャキッとした食感も魅力。長期保存性も高く世界各地で栽培されています。', 'Discover', 'Apple Varieties', 'Classic Varieties', 'Sun Fuji', 'A globally popular variety with a perfect balance of sweetness, acidity, and texture.', 'As Japan''s most iconic apple, Sun Fuji is typically harvested in mid-November. The bagless cultivation method enhances its honeycore and sweetness, complemented by a delightful crisp texture. Its superior storability has led to its cultivation worldwide.', '探索', '蘋果品種', '經典品種', '太阳富士', '甜度、酸度、口感兼備的全球人氣品種', '作為日本代表性的品種，11月中旬為產季。無袋栽培的陽光富士特別香甜且帶有果蜜，清脆的口感也是其魅力所在。保存性高，全球各地皆有栽培。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B5%E3%83%B3%E3%81%B5%E3%81%98.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0009', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'シナノリップ', '夏りんごの新定番！？ジューシーで香り豊か', '「千秋」と「シナノレッド」の交配種で、歯ごたえと果汁の多さが特徴。新しい長野県生まれの注目品種です。ポスト夏りんごの定番「つがる」！？収穫は8月中旬～下旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Shinano Lip', 'A new summer apple variety, juicy and aromatic.', 'Its season is from mid to late August. This new and noteworthy variety, born in Nagano Prefecture, is a cross between Chiaki and Shinano Red, characterized by its crunchiness and abundant juice.', '探索', '蘋果品種', '長野原創品種', '信浓唇', '新品種夏蘋果，多汁且香氣濃郁', '8月中旬至下旬為產季。是千秋 (Senko) 和信濃紅 (Shinano Red) 的雜交品種，特點是咬勁十足且果汁豐富。是長野縣新培育的矚目品種。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B7%E3%83%8A%E3%83%8E%E3%83%AA%E3%83%83%E3%83%97.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0010', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'シナノピッコロ', '名前も見た目もかわいい新品種', '「ゴールデンデリシャス」と「あかね」をかけ合わせた長野県生まれの新品種です。果肉がしっかりしていて、小さいけれど食べごたえがあります。ちなみに「ピッコロ」は、イタリア語で「小さい」という意味。収穫は9月中旬～下旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Shinano Piccolo', 'A charming new variety, delightful in both name and appearance.', 'This new variety, born in Nagano Prefecture, is a cross between ''Golden Delicious'' and ''Akane''. It has firm flesh and, despite its small size, offers a satisfying bite. Incidentally, ''Piccolo'' means ''small'' in Italian. Harvest is from mid to late September.', '探索', '蘋果品種', '長野原創品種', '信濃笛 (Shinano Piccolo)', '名字與外型皆可愛的新品種', '這是長野縣培育出的新品種，由「金冠蘋果 (Golden Delicious)」與「秋映 (Akane)」雜交而成。果肉紮實，雖然小巧卻口感十足。順帶一提，「Piccolo」在義大利語中意為「小」。採收期為9月中旬至下旬。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B7%E3%83%8A%E3%83%8E%E3%83%94%E3%83%83%E3%82%B3%E3%83%AD.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0011', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'シナノプッチ', '手のひらサイズで“丸かじり”にぴったり。水分補給はぜひプッチで', '長野県果樹試験場が「つがる」と「さんさ」を掛け合わせて育成し、2010年に品種登録した小玉りんごです。丸かじりした時に果皮が気にならないこと、果肉の褐変が遅いことなどから、丸かじりや食べきりに適した品種。シャキッとした食感と果汁の多さが特長。収穫は9月中旬～下旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Shinano Putch', 'A Nagano-born early-ripening apple, perfect for ''eating whole'' due to its palm-sized convenience.', 'This small apple variety was developed by the Nagano Prefectural Fruit Tree Experiment Station by crossing Tsugaru and Sansa, and registered in 2010. Weighing around 150-200g, its convenient size features a beautiful red skin and yellowish-white flesh, characterized by a crisp texture and abundant juice.', '探索', '蘋果品種', '長野原創品種', '信浓普奇', '掌心大小、最適合整顆啃食的長野縣早生蘋果', '長野縣果樹試驗場透過「津輕 (Tsugaru)」和「珊莎 (Sansa)」雜交培育而成，於2010年註冊品種的小顆蘋果。大小約150至200克，方便食用，果皮呈美麗的紅色，果肉為黃白色，特點是清脆的口感和豐富的果汁。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B7%E3%83%8A%E3%83%8E%E3%83%97%E3%83%83%E3%83%81.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0012', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'シナノドルチェ', '濃厚なスイーツを彷彿させるジューシーな味わい', '「ゴールデンデリシャス」と「千秋」の交配種。果汁が豊富で甘酸のバランスがよく濃厚な風味。「ドルチェ（イタリア語で甘い・スイーツ）」の名が示す通り、スイーツのような美味しさ。2005年に品種登録。当時の長野県知事・田中康夫氏が命名した。収穫は9月中旬～下旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Shinano Dolce', 'A rich and juicy flavor, just as its name suggests.', 'Its season is mid-September. It boasts abundant juice, a well-balanced sweet and tart flavor, and a rich aroma. Its name means ''sweet thing'' in Italian.', '探索', '蘋果品種', '長野原創品種', '信浓多切', '如其名，濃郁多汁的風味', '9月中旬為產季。果汁豐富，酸甜平衡，風味濃郁。其名在義大利語中意為「甜點」。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B7%E3%83%8A%E3%83%8E%E3%83%89%E3%83%AB%E3%83%81%E3%82%A7.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0013', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', '秋映', '深紅が印象的なりんご3兄弟の一つ', '長野県のオリジナル品種「りんご3兄弟」（秋映・シナノスイート・シナノゴールド）の１つ。甘味と酸味のバランスがよく、果肉は固めで香り高い。見た目の深紅が印象的で、りんごにはうるさい!?地元でも人気が高い。現在は、ほとんどを長野県で生産している。収穫は9月下旬～10月上旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Akibae', 'A deep crimson hue with a rich, intense flavor.', 'This variety, born in Nagano Prefecture, reaches its peak season in early October. It boasts a superb balance of sweetness and acidity, a firm texture, and a delightful aroma. Its striking deep crimson appearance is truly memorable.', '探索', '蘋果品種', '長野原創品種', '秋映', '帶有黑色的深紅色澤與濃郁風味。', '此品種源自長野縣，10月上旬為盛產期。甜味與酸味平衡得宜，果肉紮實且香氣濃郁。其深紅色的外觀令人印象深刻。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E7%A7%8B%E6%98%A0.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0014', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'シナノスイート', '甘くて食べやすい近年人気の品種', '長野県のオリジナル品種「りんご3兄弟」（秋映・シナノスイート・シナノゴールド）の１つ（次男）で長野県の代表的な育成品種。酸味が少なく甘さが際立つ。果汁が豊富で食感は程よい。近年は、老若男女問わず人気があり、中生種のりんごとして認知度も高まっている。収穫は10月上旬～下旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Shinano Sweet', 'A popular, sweet, and juicy variety that''s easy to enjoy.', 'Harvested in mid-October, this apple is characterized by its prominent sweetness and low acidity. It is exceptionally juicy with a pleasant texture, making it a favorite among all ages. It is a representative cultivated variety of Nagano Prefecture.', '探索', '蘋果品種', '長野原創品種', '信浓甜', '香甜多汁、易於食用的人氣品種。', '10月中旬為盛產期。酸度低，甜味突出。果汁豐富，口感適中，深受各年齡層喜愛。是長野縣具代表性的培育品種。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B7%E3%83%8A%E3%83%8E%E3%82%B9%E3%82%A4%E3%83%BC%E3%83%88.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0015', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'シナノゴールド', '長野県生まれの黄色いりんごの代表格', '長野県のオリジナル品種「りんご3兄弟」（秋映・シナノスイート・シナノゴールド）の１つ（三男）で、2016年3月に長野県で初めてとなる海外許諾契約をイタリア南チロルの「りんご生産者団体」と締結した国際的な品種。歯ごたえのある果肉と調和のとれた甘酸のバランスが魅力。保存性も比較的高い。収穫は11月下旬～12月上旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Shinano Gold', 'A golden-yellow skin with a rich sweet-tart balance.', 'In season in early November, the Shinano Gold is prized for its crisp texture and harmonious blend of sweetness and acidity. It offers excellent storability and has gained international recognition, being cultivated overseas as well.', '探索', '蘋果品種', '長野原創品種', '信浓金', '黃色果皮與濃郁的酸甜平衡。', '11月上旬為盛產期。其魅力在於紮實的果肉與酸甜的完美和諧。保存性高，是海外也有栽培的國際品種。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B7%E3%83%8A%E3%83%8E%E3%82%B4%E3%83%BC%E3%83%AB%E3%83%89.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0016', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'シナノホッペ', '子どものほっぺたのような赤さが印象的', '「あかね」と「ふじ」の交配種。果実の色づきがよく蜜が入りやすいのが特徴。果皮は濃い紅色に染まり、着色のよいものは黒っぽい紫紅色になる。中生種でありながら、ジューシーでシャキッとした歯ごたえと高い糖度が特徴。熟すと蜜入りのものも多く見られる。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Shinano Hoppe', 'Strikingly red, reminiscent of a child''s rosy cheeks.', 'A hybrid of ''Akane'' and ''Fuji Apple'', this variety is characterized by its excellent coloring and tendency to develop honeycore. The skin ripens to a deep crimson, with well-colored fruits turning a dark purplish-red. Despite being a mid-season variety, it boasts juiciness, a crisp crunchiness, and high sugar content. Many ripe fruits also feature honeycore.', '探索', '蘋果品種', '長野原創品種', '信濃頰 (Shinano Hoppe)', '如孩童臉頰般紅潤的色澤令人印象深刻', '這是「秋映 (Akane)」與「富士蘋果 (Fuji)」的雜交品種。特點是果實著色良好且容易結蜜。果皮呈現深紅色，著色優良者會帶有黑紫色。作為中生品種，其特色是多汁、清脆的咬勁與高糖度。成熟後，許多果實都能看到結蜜。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B7%E3%83%8A%E3%83%8E%E3%83%9B%E3%83%83%E3%83%9A.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0017', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'すわっこ', '長野県諏訪地方生まれのりんご', 'その名のとおり、長野県諏訪地方で生まれた品種で、大きな実が特徴の「世界一」という品種の自然交雑実生から育成された。親譲りの大きな実が特徴。収穫は9月下旬～10月上旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Suwakko', 'An apple variety originating from Nagano Prefecture''s Suwa region.', 'As its name suggests, this variety was developed in the Suwa region of Nagano Prefecture, cultivated from a naturally cross-pollinated seedling of the ''Sekai Ichi'' variety, known for its large fruit. It inherits its parent''s characteristic large fruit. Harvest is from late September to early October.', '探索', '蘋果品種', '長野原創品種', '諏訪子 (Suwakko)', '誕生於長野縣諏訪地區的蘋果', '正如其名，這是誕生於長野縣諏訪地區的品種，由以大果實為特徵的「世界一 (Sekai Ichi)」品種的自然雜交實生苗培育而成。繼承了親本的大果實特徵。採收期為9月下旬至10月上旬。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%81%99%E3%82%8F%E3%81%A3%E3%81%93.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0018', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'あいかの香り', 'ふじを親に持つ大玉', 'ふじの自然交雑実生から生まれ、大玉で果汁が多い。蜜が入りやすく甘みが強いのが特徴。品種登録の出願時は農園名から「信州藤牧」であったが、後に園主の娘の名前から「あいかの香り」に改められたそう。収穫は11月中旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Aika no Kaori', 'A large, juicy Fuji-lineage apple known for its honeycore.', 'Peaking in mid-November, Aika no Kaori is a natural cross of the Fuji apple, characterized by its impressive size and abundant juice. It is particularly prized for its tendency to develop a rich honeycore and its intense sweetness.', '探索', '蘋果品種', '長野原創品種', '爱香之香', '果實碩大、易結蜜的富士蘋果系品種', '11月中旬為盛產期。由富士蘋果的自然雜交種培育而成，果實碩大且多汁。其特色是容易結蜜，甜度高。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%81%82%E3%81%84%E3%81%8B%E3%81%AE%E9%A6%99%E3%82%8A.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0019', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', 'ムーンルージュ', '話題沸騰・映える！赤果肉りんご', '飯綱町の隣の中野市で長年、りんごの赤果肉品種を研究している吉家一雄氏が育種し、2018年に品種登録。赤果肉系品種「いろどり」（「紅玉」×「ピンクパール」）と「ふじ」を交配して生まれた。黄色い果皮にうっすら果肉の赤が透けて見え、果肉には桃色～赤色が混じる。赤果肉のりんごのなかでは、甘酸のバランスがよく、シャキッとした歯ごたえもあり、生食にも向いていて、テレビ番組で取り上げられたこともあり、近年人気を博している。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Moon Rouge', 'Buzzworthy and Visually Stunning! The Red-Fleshed Apple', 'Bred by Kazuo Yoshie, who has long researched red-fleshed apple varieties in Nakano City, adjacent to Iizuna Town, Moon Rouge was registered in 2018. It was developed by crossing the red-fleshed variety ''Irodori'' (a hybrid of Jonathan and Pink Pearl) with Fuji Apple. Pink Pearl is a pink-fleshed apple cultivar developed in 1944 by Albert Etter in California, USA. Its yellow skin subtly reveals the red flesh beneath, which is a beautiful mix of pink and red. Among red-fleshed apples, it boasts an excellent balance of sweetness and acidity, a satisfying crunchiness, and is suitable for fresh eating. Having been featured on television programs, it has gained significant popularity in recent years.', '探索', '蘋果品種', '長野原創品種', '月亮胭脂 (Moon Rouge)', '話題沸騰、吸睛亮麗！紅肉蘋果', '由長年於飯綱町鄰近的中野市研究紅肉蘋果品種的吉家一雄先生培育，並於2018年註冊品種。它是紅肉品種「彩 (Irodori)」(「紅玉 (Kogyoku)」×「粉紅珍珠 (Pink Pearl)」) 與「富士蘋果 (Fuji)」雜交而成的。黃色果皮隱約透出果肉的紅色，果肉呈現粉紅色至紅色交雜的色澤。在紅肉蘋果中，它甜酸平衡極佳，口感清脆有咬勁，適合生食，也曾被電視節目報導，近年來廣受歡迎。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%83%A0%E3%83%BC%E3%83%B3%E3%83%AB%E3%83%BC%E3%82%B8%E3%83%A5.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-06-0020', 'sheet_import', '知る', '栽培されている品種', '長野県生まれの品種', '夏あかり', '“ひと足早いりんご体験”をお届け', '「さんさ」と「陽光」を交配して、育成された極早生品種。 真夏にりんごが味わえる希少さが魅力。飯綱町では、ブラムリーとともにりんごシーズンの開始を告げる。夏の暑い時季には嬉しいさっぱりとした甘酸っぱさが味わえる。収穫は8月中旬～下旬。', 'Discover', 'Apple Varieties', 'Nagano-Bred Varieties', 'Natsuakari', 'Experience the taste of summer with an early apple from Shinshu, Iizuna Town.', 'Natsuakari is an extra-early variety developed in Nagano Prefecture, boasting a lineage from "Sansa" and "Yoko" apples. Harvested early, from mid to late August, its unique appeal lies in the rare opportunity to savor fresh apples in the heart of summer.', '探索', '蘋果品種', '長野原創品種', '夏之灯', '來自盛夏信州飯綱町的「搶先蘋果體驗」', '「夏之燈 (Natsu Akari)」是長野縣培育的極早生品種，系譜為「珊莎 (Sansa)」與「陽光 (Yoko)」。其魅力在於8月中旬至下旬即可採收，能在盛夏品嚐到蘋果的稀有性。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E5%A4%8F%E3%81%82%E3%81%8B%E3%82%8A.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-07-0002', 'sheet_import', '知る', '栽培されている品種', '海外品種', 'ブラムリーズ・シードリング', '強い酸味で料理や菓子に最適な英国品種', 'イギリス原産。偏円形の大きな果実が特徴。味は、かなり酸っぱく、生食には向かないが、加熱すると煮崩れしやすいため、加工向き。イギリスでは料理・菓子に多く用いられ、「クッキングアップルの王様」と呼ばれる。収穫は8月下旬〜9月上旬。', 'Discover', 'Apple Varieties', 'International Varieties', 'Bramley''s Seedling', 'An English variety with strong Acidity, ideal for cooking and Sweets.', 'Its season is from late August to early September. It easily breaks down when cooked, making it suitable for processing, and is known as the ''King of Cooking Apple''. In recent years, Honeycore individuals have also been observed.', '探索', '蘋果品種', '海外引進品種', '布拉姆利', '酸味強烈，最適合料理與甜點的英國品種', '產季為8月下旬至9月上旬。易於燉煮軟爛，適合加工，被譽為「料理用蘋果 (Cooking Apple) 之王」。近年來也發現有結蜜的果實。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%83%96%E3%83%A9%E3%83%A0%E3%83%AA%E3%83%BC.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-07-0003', 'sheet_import', '知る', '栽培されている品種', '海外品種', 'ベル・ド・ボスクープ', 'オランダ・ボスクープ地方発祥、希少価値の高い西洋りんご', '1856年オランダのボスクープ地方で偶然生まれた品種。英国王立園芸協会から飯綱町に譲渡された16種のひとつとして栽培が始まりました。 硬めの果肉と力強い酸味が特徴で、加熱しても煮崩れしない。飯綱町では生食としても楽しめる状態で出荷されている。果実が大きく、果皮が黄金茶色のため梨に間違えられることも。収穫は9月下旬～10月上旬。', 'Discover', 'Apple Varieties', 'International Varieties', 'Belle de Boskoop', 'Originating from the Boskoop region of the Netherlands, a highly valued Western Apple variety.', 'This variety, which originated by chance in the Boskoop region of the Netherlands in 1856, began to be cultivated in Iizuna Town as one of 16 varieties transferred from the Royal Horticultural Society of the UK. It is characterized by its firm flesh and strong Acidity. While it is positioned as a Cooking Apple suitable for cooking and processing, in Iizuna Town, it is shipped in a condition that allows it to be enjoyed For Fresh Eating.', '探索', '蘋果品種', '海外引進品種', '博士库普', '源自荷蘭博斯科普 (Boskoop) 地區，稀有珍貴的西洋蘋果品種', '此品種於1856年在荷蘭博斯科普 (Boskoop) 地區偶然誕生，作為英國皇家園藝學會 (Royal Horticultural Society) 轉讓給飯綱町的16個品種之一，開始了栽培。其特色是果肉紮實且酸味強勁，定位為適合烹飪與加工的「料理用蘋果 (Cooking Apple)」，但在飯綱町，也以可供生食的狀態出貨.', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%83%99%E3%83%AB%E3%83%BB%E3%83%89%E3%83%BB%E3%83%9C%E3%82%B9%E3%82%AF%E3%83%BC%E3%83%97.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-07-0004', 'sheet_import', '知る', '栽培されている品種', '海外品種', 'ブレナム・オレンジ', '熟期にはオレンジの差し色が入る英国品種', 'イギリス原産。イングランド ウッドストックのケンプスタ―氏が1740年頃にブレンハイム城近くで発見した。熟期になると緑色果皮の一部にオレンジ色が入る。ナッツのような独特の風味がある。生食できる熟期直前の緑色果皮の時期は爽やかな味わいが楽しめるため、サラダやチーズと合わせて食べるのもおすすめ。収穫は9月中旬～10月上旬。', 'Discover', 'Apple Varieties', 'International Varieties', 'Blenheim Orange', 'A British variety that develops orange hues when ripe.', 'Originating from England, the Blenheim Orange was discovered around 1740 by George Kempster, a basket weaver, near Blenheim Palace in Woodstock, England. As it ripens, parts of its green skin develop an orange tint. It has a unique, nutty flavor. When eaten fresh just before full ripeness, while the skin is still green, it offers a refreshing taste, making it recommended for salads and pairing with cheese. Harvested from mid-September to early October.', '探索', '蘋果品種', '海外引進品種', '布伦海姆橙', NULL, NULL, 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%83%96%E3%83%AC%E3%83%8A%E3%83%A0%E3%83%BB%E3%82%AA%E3%83%AC%E3%83%B3%E3%82%B8.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-07-0005', 'sheet_import', '知る', '栽培されている品種', '海外品種', 'エグレモント・ラセット', '茶褐色の皮で梨のような見た目', 'イギリス原産。品種名はイギリス・サセックスのエグレモント伯爵に由来する。19世紀ビクトリア時代からの古典的なイギリスのりんごで、当地では現在もその人気は保たれている。果皮がざらつき茶褐色。果実は丸く香りが強い品種。ベル・ド・ボスクープ同様その見た目から梨に間違えられることもしばしば。独特の味わいは繊細で西洋ナシを彷彿とさせる。チーズによく合う。旧三水村時代に導入されたユニークな品種。収穫は9月下旬～10月上旬。', 'Discover', 'Apple Varieties', 'International Varieties', 'Egremont Russet', 'A pear-like appearance with russet-brown skin.', 'Originating from the UK, this variety is characterized by its rough, russet-brown skin. It is a round, highly aromatic apple. This unique variety was introduced to Iizuna during the era of the former Samizu Village.', '探索', '蘋果品種', '海外引進品種', '埃格雷蒙特', '茶褐色果皮，外觀似梨', '原產於英國，果皮粗糙呈茶褐色。果實圓潤且香氣濃郁的品種。是舊三水村時代引進的獨特品種。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%A8%E3%82%B0%E3%83%AC%E3%83%A2%E3%83%B3%E3%83%88%E3%83%BB%E3%83%A9%E3%82%BB%E3%83%83%E3%83%88.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-07-0006', 'sheet_import', '知る', '栽培されている品種', '海外品種', 'グラニー・スミス', '鮮やかな緑と爽やかな酸味で人気。欧米で青りんごといえばこれ', 'オーストラリア原産。1868年にオーストラリアでマリア・アン・スミスがりんごの捨て場で偶然に育った幼木を見出し育成した。果皮は鮮やかな明緑色。サクサクした食感、ジューシーで爽やかな酸味があるため、生食のほかサラダやアップルパイに最適。飯綱産は実が締まり品質が高いと評価されている。ロックバンド・ビートルズのアップル・レコードのロゴに使用されたことでも有名。収穫は11月中旬～下旬。', 'Discover', 'Apple Varieties', 'International Varieties', 'Granny Smith', 'A popular cooking apple with vibrant green color and strong acidity.', 'Originating from Australia, this highly acidic apple is ideal for fresh eating, as well as for Apple Pie and salads. Iizuna-grown Granny Smiths are highly regarded for their firm flesh and superior quality.', '探索', '蘋果品種', '海外引進品種', '澳洲青苹果', '鮮豔翠綠，酸味強烈，廣受歡迎的料理用蘋果', '原產於澳洲，酸度強烈，除了生食，也最適合製作蘋果派和沙拉。飯綱町產的果實緊實，品質備受好評。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%82%B0%E3%83%A9%E3%83%8B%E3%83%BC%E3%83%BB%E3%82%B9%E3%83%9F%E3%82%B9.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-07-0007', 'sheet_import', '知る', '栽培されている品種', '海外品種', 'ローズマリー・ラセット', 'レモンのような爽やかな香りが特徴', 'イギリス原産。強い酸味とレモンのような爽やかな香りがある。1831年に初めて記録がある古い品種。収穫は9月中旬～下旬。', 'Discover', 'Apple Varieties', 'International Varieties', 'Rosemary Russet', 'Characterized by a refreshing lemon-like aroma.', 'Originating from England, this old variety possesses a strong acidity and a refreshing lemon-like aroma. It was first recorded in 1831. Harvested from mid to late September.', '探索', '蘋果品種', '海外引進品種', '迷迭香', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-07-0008', 'sheet_import', '知る', '栽培されている品種', '海外品種', 'フラワー・オブ・ケント', 'ニュートンが万有引力を着想したりんご', 'ケント州原産の古品種。緑地に赤縞が入る。ニュートンが「万有引力の法則」を発見するきっかけとなったりんごと言われている。いいづなアップルミュージアムに植えられており、歴史的価値の高いりんご。収穫は9月上旬～中旬。', 'Discover', 'Apple Varieties', 'International Varieties', 'Flower of Kent', 'The variety that inspired Newton''s theory of universal gravitation.', 'An ancient variety originating from Kent, it has a green skin with red stripes. This historically significant apple is planted at the Iizuna Apple Museum.', '探索', '蘋果品種', '海外引進品種', '肯特之花', '牛頓從中獲得萬有引力靈感的品種', '原產於肯特郡的古老品種。外觀為綠底帶有紅色條紋，種植於飯綱蘋果博物館。是具有高度歷史價值的蘋果。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-08-0021', 'sheet_import', '知る', '栽培されている品種', 'その他注目品種', '黄王', '鮮やかな黄色の果皮と、豊かな果汁が魅力の早生りんご', '「きおう」は岩手県園芸試験場で「王林」×「千秋」の交配から生まれ、1994年に品種登録された黄色系の早生種です。 果皮は黄緑から黄色へと変化し、「黄色い王様」という意味の名に相応しい風貌。果肉はやや硬めで緻密、甘みの中にさわやかな酸味と豊富な果汁を備えており、「和梨のような食感」と評されることもあります。', 'Discover', 'Apple Varieties', 'Specialty Varieties', 'Kiou', 'An early-season apple captivating with its vibrant yellow skin and rich, refreshing juice.', '"Kiou," meaning "Yellow King," is a yellow-skinned, early-season variety registered in 1994, originating from a cross of "Orin" and "Chiaki" at the Iwate Prefectural Horticultural Experiment Station. Its skin transitions from yellowish-green to a brilliant yellow, living up to its regal name. The flesh is firm and dense, offering a delightful balance of sweetness and refreshing acidity, along with abundant juice. It is often praised for its unique "Japanese pear-like texture."', '探索', '蘋果品種', '人氣注目品種', '黄王', '果皮呈鮮豔黃色，果汁豐沛，魅力十足的早生蘋果', '「黃王 (Kioh)」是岩手縣園藝試驗場由「王林 (Ohlin)」與「千秋 (Senshu)」雜交培育而成，於1994年註冊的黃色系早生品種。果皮從黃綠色轉變為黃色，外觀與其「黃色之王」的名稱相符。果肉略硬且細緻，甜味中帶有清爽的酸度與豐富的果汁，有時被譽為「口感如同日本梨」。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E9%BB%84%E7%8E%8B.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-08-0024', 'sheet_import', '知る', '栽培されている品種', 'その他注目品種', 'トキ', NULL, NULL, 'Discover', 'Apple Varieties', 'Specialty Varieties', NULL, NULL, NULL, '探索', '蘋果品種', '人氣注目品種', NULL, NULL, NULL, 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%83%88%E3%82%AD.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-04-08-0026', 'sheet_import', '知る', '栽培されている品種', 'その他注目品種', 'ぐんま名月', '蜜が入りやすく甘さが際立つ黄色品種', '11月上旬が旬。果肉はジューシーで蜜が霜降り状に入る。甘みが非常に強く、保存性にも優れ人気急上昇中です。', 'Discover', 'Apple Varieties', 'Specialty Varieties', 'Gunma Meigetsu', 'A yellow variety known for its prominent sweetness and honeycore.', 'Harvested in early November, this apple boasts juicy flesh with a beautiful marbling of honeycore. Its intense sweetness and excellent storability have made it rapidly popular.', '探索', '蘋果品種', '人氣注目品種', '群马名月', '容易結蜜且甜度出眾的黃色品種', '11月上旬為產季。果肉多汁，果蜜呈霜降狀分佈。甜度極高，保存性也優異，人氣正迅速攀升。', 'https://appletown-iizuna.s3.ap-northeast-1.amazonaws.com/apples/images/%E3%81%90%E3%82%93%E3%81%BE%E5%90%8D%E6%9C%88.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-09-00-0011', 'sheet_import', '知る', '飯綱町のりんご愛', NULL, 'いいづなアップルミュージアム', 'りんごをめぐる常識を覆すユニークな展示が楽しめる博物館。', 'いいづなアップルミュージアムは、りんごに関連するあらゆる品を集めた全国でも珍しい施設です。歴史や品種解説のほか、アップルパイやりんご柄のファッション、さらには「リンゴ追分」のレコードや初代Macまで並びます。屋外にはニュートンのりんごの木を含む海外品種18種類が植えられ、絶滅危機を乗り越えた希少な和りんご「高坂りんご」も見学可能。展示の型破りさと学びが同居する、訪れる人を驚かせるスポットです。', 'Discover', 'Apple Culture', NULL, 'Iizuna Apple Museum', 'A museum offering unique exhibits that challenge conventional perceptions of apples.', 'The Iizuna Apple Museum is a rare facility in Japan, showcasing an extensive collection of apple-related artifacts. Beyond delving into the history and detailed explanations of various apple varieties, the museum''s eclectic displays range from Apple Pies and apple-themed fashion to records of the iconic song ''Ringo Oiwake'' and even the original Mac computer. Outdoors, visitors can explore 18 foreign apple varieties, including Newton''s Apple Tree, and observe the ''Kosaka Apple,'' a native Japanese variety that has been brought back from the brink of extinction. This captivating destination offers a surprising blend of unconventional exhibits and profound learning, sure to astonish all who visit.', '探索', '蘋果文化', NULL, '飯綱蘋果博物館', '顛覆您對蘋果的既有認知，充滿獨特展示的博物館。', '飯綱蘋果博物館是日本全國少見、匯集所有蘋果相關物品的設施。除了介紹蘋果的歷史和品種，館內還陳列著蘋果派、蘋果圖案的時尚服飾，甚至有「蘋果追分 (Ringo Oiwake)」的唱片和初代Mac電腦。戶外種植了18種外國蘋果，包括牛頓蘋果樹，以及成功擺脫滅絕危機的日本原生蘋果「高坂蘋果 (Kosaka Apple)」。這是一個將顛覆傳統的展示與豐富學習融為一體，讓所有訪客驚嘆不已的景點。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/bd27e610-8eef-013e-f63d-0a58a9feac02/____01.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/bd267ef0-8eef-013e-f63c-0a58a9feac02/76519-160-d9742160a9f1212f9d405dedc54f1bd8-3900x2194.jpeg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/bd20b910-8eef-013e-f639-0a58a9feac02/___________-____.jpg', NULL, NULL, NULL, 'https://mitsudon-marche.jp/blogs/blog/2023032?srsltid=AfmBOoonRxqIxmImJ8dvYx1nlmU31gehXE9OYs2T6YkDmgR5_Tmg6D1y', NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/iizuna_applemuseum/?hl=ja', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-09-00-0012', 'sheet_import', '知る', '飯綱町のりんご愛', NULL, '公式ファンクラブ「いいづなリンゴ部」', '飯綱町公式ファンクラブ。部員限定の情報や特典盛りだくさん', '「いいづなリンゴ部」は、飯綱町と楽天グループが連携して立ち上げた飯綱町の公式ファンクラブです。飯綱町の観光や移住、ふるさと納税などの最新情報を発信しています。飯綱町産りんごのお得な入手や来季分の先行予約など、りんご好きには特典が盛りだくさん。さらに、応援ボタンやふるさと住民登録制度を通じて、地域とファンがより深く結びつく仕掛けが用意されています。', 'Discover', 'Apple Culture', NULL, 'Official Fan Club: Iizuna Apple Club', 'An initiative connecting you with the region through exclusive member information and benefits.', 'The Iizuna Apple Club is an official fan club that delivers the latest information on tourism, relocation, and Hometown Tax Donation via email newsletters. In collaboration with Rakuten Group, members receive benefits such as Rakuten points and Hometown Tax Donation perks. It offers delightful advantages for apple lovers, including discounted Value Grade Apples and priority reservations for next season''s harvest. Furthermore, mechanisms like support buttons and the Furusato Resident Registration System are in place to foster deeper connections between the region and its fans.', '探索', '蘋果文化', NULL, '官方粉絲俱樂部「飯綱蘋果社」', '透過會員限定資訊與專屬優惠，與飯綱町建立更深連結的企劃。', '「飯綱蘋果社」是一個官方粉絲俱樂部，透過電子報發送觀光、移居、故鄉納稅等最新資訊。與樂天集團合作，會員可享有樂天點數回饋及故鄉納稅特典等優惠。此外，還提供以優惠價格購買特惠蘋果、預購下一季蘋果等令蘋果愛好者欣喜的機制。透過應援按鈕和故鄉居民登記制度，飯綱町與粉絲之間建立了更深層次的連結。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/c25a72c0-8eef-013e-f641-0a58a9feac02/nagano_iiduna.jpg', NULL, NULL, NULL, NULL, NULL, 'https://event.rakuten.co.jp/area/iizuna/fanclub/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-09-09-0010', 'sheet_import', '知る', '飯綱町のりんご愛', 'みつどん', 'PRキャラクター「みつどん」', '星形の甘い蜜を宿したりんごの妖精。', 'みつどんは、星形の蜜を宿したりんごの妖精です。「ふじ」をスターカットと呼ばれる輪切りにしたときにあらわれる星形の蜜をモチーフにしたもので、真っ赤な姿はまさに旬のりんごそのもの。年齢は「永遠に食べごろ」で、趣味は日向ぼっこ。好きなものは自然や仲間、そして飯綱町の人たちです。性格は控えめながら働き者で、時には飯綱町産りんごの魅力を伝えるためにぐいぐい前へ出ることもあります。大きな階段はちょっぴり苦手ですが、明るい笑顔と優しさでみんなを元気にしてくれる存在です。', 'Discover', 'Apple Culture', 'Mitsudon: Town Mascot', 'PR Character "Mitsudon"', 'An energetic apple fairy with sweet honey in the shape of a star on his face.', 'Mitsudon is a mysterious fairy whose face bears the sweet honey of an apple. The star shape on his face is inspired by the honeycore of a Fuji Apple, and his moderately tanned appearance perfectly embodies a ripe, in-season apple. His age is "eternally in its prime," and his hobby is sunbathing. He loves nature, his friends, and the people of Iizuna Town. Though modest, Mitsudon is a diligent worker, sometimes stepping forward to passionately convey the charm of Iizuna apples. While he''s a little shy around large staircases, his bright smile and kindness uplift everyone around him.', '探索', '蘋果文化', '吉祥物「Mitsudon」', '宣傳吉祥物「蜜咚」', '臉上鑲嵌著甜美果蜜星辰，總是充滿活力的蘋果精靈。', '蜜咚是臉上鑲嵌著蘋果蜜的奇妙精靈。臉上的星形圖案是以蜜汁豐沛的「富士蘋果」為靈感，而其適度曬黑的模樣，正是當季蘋果的最佳寫照。蜜咚的年齡是「永遠的品嚐最佳時機」，興趣是曬太陽。牠喜歡大自然、夥伴，以及飯綱町的人們。蜜咚個性內斂卻勤奮，有時為了傳達飯綱蘋果的魅力，也會積極向前。雖然有點不擅長大階梯，但牠開朗的笑容與溫柔，是帶給大家活力的存在。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/3bb6c340-8d6a-013e-ae9b-0a58a9feac02/20231120_mitsudon-11.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/5c710a10-8d6a-013e-1674-0a58a9feac02/20240124_mitsudon-17.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/5127e1e0-8d6a-013e-aeb7-0a58a9feac02/20240109_mitsudon-goods-16.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/5c93f9f0-8d6a-013e-bca7-0a58a9feac02/20240501_mitsudonT-5.jpg', NULL, NULL, 'https://www.youtube.com/@mitsudondon', NULL, NULL, NULL, NULL, 'https://mitsudon-marche.jp/collections/mitsudon?srsltid=AfmBOorPD_L2QCF4ywuKjQVxjhB3YnW6K1-cqQ-qbo3UFKFr7z1qTBDP', 'https://www.instagram.com/iiduna1127/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('02-09-09-0013', 'sheet_import', '知る', '飯綱町のりんご愛', 'みつどん', 'みつどんベレー帽', '地域おこし協力隊考案のハンドメイド帽子。作り手は町内のおばあちゃんたち！ご注文はこちら', 'みつどんをもっと身近にPRできる方法はないかと考えた地域おこし協力隊の発案・企画によって誕生したベレー帽。「かわいい！」という反響が相次いだことを受け、牟礼駅舎の座布団などを作っている有志の団体「こぶし会」協力のもと、町内の保育園園児全員分を作るプロジェクトを決行（2025年）。町民運動会で揃いのベレー帽をかぶった園児たちが「みつどん音頭」を踊る姿は、大きな話題となりました。現在は、完全受注生産で製作しています。', 'Discover', 'Apple Culture', 'Mitsudon: Town Mascot', 'Mitsudon Beret Hats', 'Handmade hats designed by Local Vitalization Cooperators. Click here to order.', 'The Mitsudon Beret Hat was created from the idea of finding a way to promote Mitsudon more intimately. Despite receiving enthusiastic feedback like "Cute!", making them for personal use was already a challenge. At that time, we connected with the Kobushi-kai, a local craft group that makes items like cushions for the station building, and launched a project to create hats for all preschool children. In response to requests to "Please sell them!", the hats are now produced for event-limited sales and made-to-order.', '探索', '蘋果文化', '吉祥物「Mitsudon」', '蜜咚貝雷帽', '由地方創生協力隊發想的手工帽子。如欲訂購，請點擊此處。', '為了讓蜜咚的形象更貼近大眾，蜜咚貝雷帽應運而生。雖然廣受好評，但起初僅能勉強製作自己的份。後來，透過與製作車站坐墊等的こぶし會 (Kobushi-kai) 合作，成功推動了為所有幼兒園學童製作貝雷帽的計畫。應廣大「希望能販售！」的呼聲，目前僅限活動現場或採完全接單生產的方式製作販售。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/d88810a0-a006-013e-d3fe-0a58a9feac02/%E3%81%BF%E3%81%A4%E3%81%A8%E3%82%99%E3%82%93%E3%83%98%E3%82%99%E3%83%AC%E3%83%BC%E5%B8%BD%E2%91%A0.JPG', NULL, NULL, NULL, NULL, NULL, NULL, 'https://forms.gle/BSg9PVssyfqbbVqa8', 'ご注文はこちら', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://forms.gle/BSg9PVssyfqbbVqa8', NULL),
('10-10-00-0001', 'sheet_import', '味わう', 'りんごが買えるお店', NULL, 'いいづなマルシェ むーちゃん', 'カフェ・テラス併設の直売所。お土産の購入もおすすめ', 'cafe Apple Terraceを備え、町内産の果物や野菜を使ったスムージー、ジェラートなどが味わえます。北信五岳を望むテラスも併設。店内は、夏には、キュウリやナス、ピーマン、ボタンコショウなど地場の採れたて野菜が並び、りんごのシーズンが始まると売場の半分は多種多様なりんごに。米の量り売りも行っており、好きな品種をその場で精米して持ち帰ることができます。町内農家各々のりんごジュースやジャム、シードルの品揃えも豊富。お土産の購入はぜひ、むーちゃんで。', 'Savor', 'Where to Buy', NULL, 'Mu-chan', 'A farm stand with an attached cafe, offering farming experiences, where visitors can experience local life.', 'Featuring the attached cafe ''Apple Terrace,'' where you can savor smoothies and Gelato made with freshly harvested fruits and vegetables. It also provides a rice milling service, allowing you to take home freshly milled rice immediately after purchase. This farm stand serves as a consultation hub for Farming Experience and has a system in place to welcome those interested in apple cultivation, truly connecting the Community with its people.', '品味', '蘋果販售據點', NULL, '姆醬飯綱市集 (Ii-zuna Marche Mu-chan)', '附設咖啡廳，提供農事體驗。感受在地生活的農產物直銷所。', '附設「蘋果露台 (Apple Terrace)」咖啡廳，您可品嚐到使用現採水果和蔬菜製成的果昔與義式冰淇淋等。此外，這裡也提供米穀精米服務，讓您購買後能立即將精米帶回家。作為農事體驗的諮詢窗口，姆醬飯綱市集也設有接納對蘋果栽培有興趣人士的機制，是連結在地與人們的農產物直銷所。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/71f552f0-8efa-013e-b948-0a58a9feac02/1205174419_61ac7be30535a.jpeg', NULL, NULL, NULL, NULL, NULL, 'https://www.iizuna-furusato.com/iizuna-muchan', NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/iizunamu_chan.apple_terrace/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-10-00-0002', 'sheet_import', '味わう', 'りんごが買えるお店', NULL, '農産物直売所 さんちゃん', '三水のりんごがあつまる老舗直売所。', '旧三水村時代からつづく老舗の直売所。三水地区の農家が手掛けたりんごが集まる。「飯綱町産のりんごを買うならココが一番！」というお客も多く、りんごのシーズンになると、県内外から来客。「サンふじ」の時季に行うコンテナ販売「ふじ祭り」には長蛇の列ができるほど。アップルパイやおやきなど、地元農家の手作り加工品も豊富。小さな直売所ならではの温かさがあり、生産者と顔を合わせやすいのも魅力。飲食店「日和」隣接。', 'Savor', 'Where to Buy', NULL, 'San-chan', 'A small farm stand where handmade processed goods and local interactions are highlights.', 'This farm stand is abundant in handmade processed goods, offering Apple Juice, jam, and Apple Pie, allowing you to enjoy not only fresh fruits but also delicious processed products. Its charm lies in the warmth unique to a ''small farm stand'' and the approachable scale that makes it easy to meet the producers face-to-face. With a well-maintained parking lot, it''s an ideal spot to stop by during your journey.', '品味', '蘋果販售據點', NULL, '三醬農產物直銷所 (San-chan)', '小巧的農產物直銷所，以手工加工品和在地交流為亮點。', '這是一個手工加工品豐富的農產物直銷所。販售蘋果汁、果醬、蘋果派等商品，不僅能享用新鮮水果，也能品嚐到加工品。其魅力在於「小巧農產物直銷所」特有的溫馨感，以及容易與生產者面對面交流的規模。停車場設施完善，是旅途中方便順道造訪的景點。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/71f6cae0-8efa-013e-26c3-0a58a9feac02/sanchan-top1.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.iizuna-furusato.com/sanchann', NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/sansan.sanchan/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-10-00-0003', 'sheet_import', '味わう', 'りんごが買えるお店', NULL, '四季彩', '地元パンや雪むろ熟成品も。品揃えの広さが光る直売所。', '地元ベーカリーや菓子類も並ぶ農産物直売所。さらに「雪むろ」で熟成させた 雪ねむりりんご など、ここでしか味わえない商品を提供しています。隣接するりんご園では収穫体験もできるため、買う楽しみと体験が一体化。多彩なラインナップで観光客から地元客まで支持を集めています。', 'Savor', 'Where to Buy', NULL, 'Shikisai', 'A farm stand boasting a wide selection, including local bread and Snow-aged products.', 'This farm stand features local bakery items and Sweets. Furthermore, it offers unique products that can only be tasted here, such as Yuki-nemuri Apple, Snow-aged in a ''Snow Cellar.'' As Harvesting Experience are also available at the adjacent apple orchard, the joy of shopping and the experience become one. Its diverse lineup attracts support from both tourists and locals.', '品味', '蘋果販售據點', NULL, '四季彩直銷所 (Shikisai)', '在地烘焙點心與雪室熟成商品，品項豐富的農產物直銷所。', '這是一個陳列在地烘焙坊麵包和糕點類的農產物直銷所。此外，還提供獨特的商品，例如在「雪室」中熟成的雪藏熟成蘋果。鄰近的蘋果園也提供採摘體驗，讓購物樂趣與體驗融為一體。豐富多元的商品陣容，深受觀光客與在地顧客的喜愛。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/71f692b0-8efa-013e-b949-0a58a9feac02/shikisai_top2.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.iizuna-furusato.com/shikisai', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-10-00-0004', 'sheet_import', '味わう', 'りんごが買えるお店', NULL, 'みつどんマルシェ', 'オンラインで全国へ。希少りんごや食べ比べ便も展開。', 'みつどんマルシェは、全国配送に対応する通販サイト で、遠方からでも気軽にりんごを注文できます。希少品種を含む50品種規模 を扱い、「30品種食べ比べ定期便」などユニークな企画が魅力。ふるさと納税返礼品との連動もあり、地域産品の販路拡大を担う公式ECサイトです。', 'Savor', 'Where to Buy', NULL, 'Mitsudon Marche', 'Connecting Iizuna''s unique apple varieties to the world, offering rare apples and curated tasting sets online.', 'Mitsudon Marche is Iizuna Town''s official online store, providing nationwide shipping for easy apple orders from anywhere. It features an extensive selection of approximately 50 apple varieties, including rare ones, and offers unique plans such as the "30-Variety Tasting Comparison Subscription Box." Integrated with Hometown Tax Donation return gifts, it plays a crucial role in expanding sales channels for Iizuna''s local produce.', '品味', '蘋果販售據點', NULL, '蜜咚市集', '線上購物，全國配送。提供稀有蘋果品種及品嚐比較組合。', '蜜咚市集是一個提供全國配送服務的網購平台，讓遠方的顧客也能輕鬆訂購飯綱町的蘋果。這裡匯集了約50種稀有蘋果品種，並推出「30種蘋果品嚐比較定期配送組合」等獨特企劃，極具魅力。此外，蜜咚市集也與故鄉納稅回禮品制度結合，是負責拓展當地農產品銷售通路的官方電子商務網站。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/d5966910-8efa-013e-26d3-0a58a9feac02/mitsudon-marche-logo.jpeg', NULL, NULL, NULL, NULL, NULL, 'https://mitsudon-marche.jp/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-11-00-0013', 'sheet_import', '味わう', '生産者', NULL, '飯綱みはらし農園', 'サンプルリード', 'サンプル本文', 'Savor', 'Meet the Growers', NULL, NULL, NULL, NULL, '品味', '走訪生產者', NULL, NULL, NULL, NULL, 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/c4b8c420-8d6a-013e-4d81-0a58a9feac02/%E3%81%A4%E3%81%8B%E3%82%99%E3%82%8B-1.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://iizuna.jp/docs/10651.html', '現役隊員に聞く、飯綱町地域おこし協力隊のリアルなあれこれ！', NULL, NULL, 'https://iizuna-miharashi-f24.stores.jp/', 'https://www.instagram.com/iizuna_miharashi_farm', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://iizuna-flyer-studio.vercel.app/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-12-00-0006', 'sheet_import', '味わう', '加工品', NULL, 'りんごジャム', '果肉の色や風味を生かした多彩なりんごジャムが各地で販売。', '飯綱町のりんごジャムは、多品種栽培の特色を反映し、ふじや紅玉のほか、英国りんごや赤果肉品種「メイポール」など個性豊かな味わいが楽しめます。メイポールジャムを使った焼き菓子「メイポールさんど」は県のコンクールで入賞した実績もあります。販売はアップルミュージアムや町内直売所、サンクゼールなどで行われ、公式通販「みつどんマルシェ」でも購入可能です。ワインと並ぶ特産品として、地域の恵みを象徴する一品です。', 'Savor', 'Artisan Products', NULL, 'Apple Jam', 'A vibrant array of apple jams, each preserving the distinct color and flavor of Iizuna''s diverse apple harvest, are available across the region.', 'Reflecting the town''s characteristic multi-variety cultivation, Iizuna Town''s Apple Jam offers unique flavors from Fuji Apple and Jonathan, alongside British apples and the distinctive red-fleshed Maypole. The baked good "Maypole Sando," crafted with Maypole jam, has even received awards in prefectural competitions. These exquisite jams can be purchased at the Iizuna Apple Museum, local Farm Stands, St. Cousair, and through the official online store, Mitsudon Marche. As a specialty product alongside wine, Iizuna''s apple jam symbolizes the rich bounty of the region.', '品味', '蘋果加工精品', NULL, '蘋果果醬', '活用多樣蘋果品種的果肉色澤與風味，推出各式蘋果果醬。', '飯綱町的蘋果果醬，充分展現了多品種栽培的特色。除了富士蘋果和紅玉蘋果外，還能品嚐到英國蘋果以及紅肉蘋果品種「梅波 (Maypole)」等獨具風味的果醬。其中，使用梅波 (Maypole) 果醬製成的烘焙點心「梅波夾心餅乾」，更曾榮獲縣級競賽獎項。這些果醬可在飯綱蘋果博物館、町內農產物直銷所、St. Cousair等地購買，也可透過官方網購平台「蜜咚市集」訂購。蘋果果醬與蘋果酒並列為飯綱町的特產，象徵著這片土地的豐饒恩賜。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/9de3a120-8d6a-013e-bce1-0a58a9feac02/jam-5.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/8ae47220-8d6a-013e-bcd4-0a58a9feac02/IMG_2439.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-12-00-0007', 'sheet_import', '味わう', '加工品', NULL, 'りんごジュース', '多彩な品種を活かしたジュースは、飲み比べも楽しめる人気の加工品。', '町内でつくられるりんごジュースは、50品種以上のりんごを活かした多彩なバリエーションが特徴です。ふじの濃厚な甘み、つがるの爽やかな酸味など、品種ごとの味わいの違いを飲み比べられます。赤果肉りんごを使ったジュースは鮮やかな赤色が残り、見た目にも華やかです。直売所やオンラインショップ「みつどんマルシェ」でも購入でき、ふるさと納税の返礼品としても人気を集めています。', 'Savor', 'Artisan Products', NULL, 'Apple Juice', 'Showcasing the versatility of Iizuna''s diverse apple varieties, these popular processed juices are perfect for delightful tasting comparisons.', 'The Apple Juice produced in Iizuna Town is renowned for its wide range of variations, utilizing over 50 apple varieties. Consumers can savor the distinct flavor profiles of each variety, from the rich sweetness of Fuji Apple to the refreshing acidity of Tsugaru. Juices made from Red-fleshed Apples boast a vibrant red hue, making them visually appealing. These juices are available at Farm Stands and the online store Mitsudon Marche, and are also highly sought after as Hometown Tax Donation return gifts.', '品味', '蘋果加工精品', NULL, '蘋果汁', '活用多樣品種的蘋果汁，是能享受品嚐比較樂趣的熱門加工品。', '飯綱町生產的蘋果汁，以活用50種以上蘋果品種的多樣化風味為特色。您可以品嚐比較不同品種的蘋果汁，例如富士蘋果的濃郁甜味，或是津輕蘋果的清爽酸度。使用紅肉蘋果製成的果汁，則保留了鮮豔的紅色，視覺上更添華麗。這些蘋果汁可在農產物直銷所及線上網購平台「蜜咚市集」購買，同時也是故鄉納稅回禮品中的人氣商品。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/09be0fd0-8d6a-013e-0566-0a58a9feac02/20230320_yamaju-2.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/1251db70-8d6a-013e-f608-0a58a9feac02/20230517_maruyama-5.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/1f288840-8d6a-013e-ae64-0a58a9feac02/20230706_izumigaoka-9.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-12-00-0008', 'sheet_import', '味わう', '加工品', NULL, 'シードル', '個性あるりんごのお酒が、新しい食文化を広げています。', '町内には二つの醸造所があり、それぞれに特色あるシードルを生み出しています。旧小学校を改装した「林檎学校醸造所」では委託製造も行い、学びの場として文化の普及を目指しています。サンクゼール・ワイナリー本店では、珍しい品種を使った限定シードルが登場し、飲み比べも楽しめます。また、幻の和りんご「高坂りんご」や摘果りんごの活用も進み、多彩な味わいとストーリーを持つシードルが地域の魅力を発信しています。', 'Savor', 'Artisan Products', NULL, 'Cider', 'Unique apple beverages are expanding a new culinary culture.', 'Iizuna Town is home to two distinctive cideries, each crafting unique ciders. The Ringo School Cidery, housed in a renovated former elementary school, also offers contract manufacturing and aims to spread cider culture as a hub for learning. At the St. Cousair Winery Main Store, limited-edition ciders made from rare apple varieties are available for tasting comparisons. Furthermore, the utilization of the elusive native Japanese apple, Kosaka Apple, and Thinned Apples is advancing, with ciders boasting diverse flavors and stories that showcase the region''s charm.', '品味', '蘋果加工精品', NULL, '蘋果酒', '獨具個性的蘋果酒，正在拓展全新的飲食文化。', '町內設有兩座釀造所，各自釀造出獨具特色的蘋果酒。其中，「蘋果學校釀造所」由舊小學改建而成，不僅提供委託釀造服務，更致力於推廣蘋果酒文化，成為一個學習交流的場域。而在聖庫澤爾酒莊本店 (St. Cousair Winery Hon Ten)，則能品嚐到使用珍稀品種釀製的限定蘋果酒，讓您盡情享受品嚐比較的樂趣。此外，透過活用夢幻般的日本原生蘋果「高坂蘋果 (Kosaka Apple)」以及疏果蘋果，飯綱町正積極推廣擁有豐富風味與故事的蘋果酒，向世界傳遞在地魅力。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/1252b880-8d6a-013e-a811-0a58a9feac02/20230502_JAL-4.jpg', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/27946bd0-8d6a-013e-ae75-0a58a9feac02/20230707_cidre-1.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-13-00-0009', 'sheet_import', '味わう', 'イベント', NULL, '英国りんごフェア', '酸味豊かな品種の魅力を伝える催しが毎年秋に開かれます。', '毎年秋に開催される英国りんごフェアは、飯綱町で育つ海外品種のクッキングアップルを広く紹介する催しです。1990年に英国王立園芸協会から16種類が寄贈されたことをきっかけに、町内では現在、約18種類が栽培されています。なかでも酸味豊かな「ブラムリーズ・シードリング」や「グラニー・スミス」は、アップルパイや肉料理に最適と評判です。フェア期間中は料理研究家による実演やレシピ公開も行われ、個性的なりんごの使い方に触れることができます。', 'Savor', 'Seasonal Events', NULL, 'British Apple Fair', 'An annual autumn event highlights the appeal of tart apple varieties.', 'Held every autumn, the British Apple Fair is an event that widely introduces the foreign cooking apple varieties grown in Iizuna Town. The initiative began in 1990 with the donation of 16 varieties from the Royal Horticultural Society (RHS), and currently, approximately 18 varieties are cultivated in the town. Among them, the richly acidic Bramley''s Seedling and Granny Smith are highly regarded as ideal for Apple Pie and meat dishes. During the fair, cooking researchers provide demonstrations and share recipes, offering insights into unique ways to use these distinctive apples.', '品味', '季節活動與慶典', NULL, '英國蘋果節', '每年秋季舉辦的盛會，旨在傳遞酸度豐富蘋果品種的獨特魅力。', '每年秋季舉辦的英國蘋果節，是一場廣泛介紹飯綱町栽種的海外料理用蘋果的盛會。1990年，英國皇家園藝協會捐贈了16個品種，以此為契機，町內目前約有18種英國蘋果被栽培。其中，酸度豐富的「布蘭利 (Bramley''s Seedling)」和「史密斯奶奶 (Granny Smith)」等品種，因其最適合製作蘋果派和肉類料理而廣受好評。活動期間，料理研究家將進行現場示範並公開食譜，讓參與者有機會接觸到這些獨特蘋果的多元料理方式。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/cd850820-8d6a-013e-c3bf-0a58a9feac02/%E3%83%95%E3%82%99%E3%83%A9%E3%83%A0%E3%83%AA%E3%83%BC_5.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.neri.or.jp/www/contents/1756080392973/index.html', NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/iizuna_ringofair_official/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-13-00-0010', 'sheet_import', '味わう', 'イベント', NULL, 'りんごスイーツフェア', '多彩なスイーツや飲み物を通じて、りんごの魅力を感じることができます。', '「りんごスイーツフェア」では、町内外の店舗で多様なりんごスイーツが登場します。アップルブランデーを使ったカルヴァドスケーキや、赤肉りんごを使った焼き菓子など、個性豊かな商品が並ぶのも魅力のひとつです。さらに、ホットアップルサイダーを新名物として提案するなど、新しい楽しみ方も模索されています。加えて、酸味が強いブラムリーやグラニー・スミスなどの料理用りんごを活用したレシピ発信を通じて、日本ではまだ馴染みの薄い食文化を広げる取り組みも進められています。', 'Savor', 'Seasonal Events', NULL, 'Apple Sweets Fair', 'Experience the charm of apples through a variety of sweets and beverages.', 'During the Apple Sweets Fair, a diverse array of Apple Sweets appears at stores both within and outside Iizuna Town. One of the attractions is the lineup of unique products, such as Calvados cake made with apple brandy and Baked Goods featuring Red-fleshed Apples. Efforts are also underway to explore new ways to enjoy apples, including proposing Hot Apple Cider as a new local specialty. Additionally, initiatives are progressing to popularize a food culture less familiar in Japan by promoting recipes that utilize tart cooking apples like Bramley''s Seedling and Granny Smith.', '品味', '季節活動與慶典', NULL, '蘋果甜點節', '透過各式各樣的甜點和飲品，感受蘋果的迷人魅力。', '在「蘋果甜點節」期間，町內外的店家將推出各式各樣的蘋果甜點。其中一大魅力便是琳瑯滿目的獨特商品，例如使用蘋果白蘭地製成的蘋果白蘭地蛋糕，以及用紅肉蘋果製作的烘焙點心等。此外，飯綱町也積極探索新的享用方式，例如將熱蘋果酒作為新名產推廣。同時，透過發布活用酸度較高的布蘭利 (Bramley''s Seedling) 和史密斯奶奶 (Granny Smith) 等料理用蘋果的食譜，致力於推廣在日本尚不普及的飲食文化。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/iizuna_ringofair_official/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-13-00-0011', 'sheet_import', '味わう', 'イベント', NULL, 'いいづなりんごスイーツコンクール', 'プロと町民が審査する独自のコンクールで、新しいりんごの魅力を発信。', '「いいづなりんごスイーツコンクール」は、全国のパティシエが飯綱町産りんごを使ったお菓子で腕を競うイベントです。審査では「りんごの味や香りを最大限に生かすこと」が最重要視され、作品は常温で1日保管できる条件が設けられています。農家を訪れるツアーを通じて品種や栽培方法を学ぶ機会もあり、生産者とパティシエの交流が生まれています。受賞作はふるさと納税返礼品や首都圏アンテナショップで紹介されるなど、地域と食文化をつなげる取り組みとして広がりを見せています。', 'Savor', 'Seasonal Events', NULL, 'Iizuna Apple Sweets Competition', 'A unique competition judged by professionals and townspeople, showcasing the new appeal of apples.', 'The Iizuna Apple Sweets Competition is an event where patissiers from across Japan compete with sweets made from Iizuna-grown apples. The judging places the utmost importance on maximizing the flavor and aroma of the apples, and entries must be able to be stored at room temperature for one day. Opportunities to learn about apple varieties and cultivation methods through farm tours foster interaction between producers and patissiers. Award-winning creations are featured as Hometown Tax Donation return gifts and introduced at Regional Product Shops in the Tokyo metropolitan area, expanding this initiative that connects the region with its food culture.', '品味', '季節活動與慶典', NULL, '飯綱蘋果甜點大賽', '由專業人士與町民共同評審的獨特競賽，發掘蘋果新魅力。', '「飯綱蘋果甜點大賽」是全國甜點師傅們使用飯綱町產蘋果製作甜點一較高下的盛事。評審最重視的是「最大限度地發揮蘋果的風味與香氣」，作品必須符合常溫下可保存一天的條件。透過參訪農家的行程，也有機會學習蘋果品種與栽培方法，促進了生產者與甜點師傅之間的交流。得獎作品不僅作為故鄉納稅的回禮品，也在首都圈的地方特產展售店中推廣，這項連結地方與飲食文化的活動正日益擴大。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.neri.or.jp/www/contents/1743146218997/index.html', NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/iizuna_ringofair_official/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('10-13-00-0012', 'sheet_import', '味わう', 'イベント', NULL, 'ふじまつり', '毎年多くの人で賑わう、ふじりんごに特化した人気の祭り。', 'ふじまつりは、冬に旬を迎える「ふじ」りんごを楽しむ恒例イベントです。開始から2時間で完売することもあるほどの人気で、県外からも多くの来場者が訪れます。会場では箱売りやコンテナ売りが飛ぶように売れ、常連客は数箱まとめて購入し親戚や近所に配るのが定番。袋をかけて栽培する「ふじ」と、太陽光を浴びた「サンふじ」が並び、それぞれの味わいを楽しめるのも魅力のひとつです。', 'Savor', 'Seasonal Events', NULL, 'Fuji Apple Festival', 'A popular festival dedicated to Fuji Apples, bustling with many visitors every year.', 'The Fuji Apple Festival is an annual event celebrating the Fuji Apple, which reaches its peak season in winter. It is so popular that items sometimes sell out within two hours of opening, attracting many visitors from outside the prefecture. At the venue, Fuji Apples are sold rapidly by the box and container, with regular customers often buying several boxes to share with relatives and neighbors. A unique charm of the festival is the opportunity to compare the taste of Fuji Apples, which are cultivated with bags, and Sun Fuji Apples, which are exposed to direct sunlight.', '品味', '季節活動與慶典', NULL, '富士蘋果祭', '每年都吸引眾多人潮，專為富士蘋果舉辦的熱門慶典。', '富士蘋果祭是每年冬季，為品嚐當季「富士蘋果」而舉辦的例行活動。其受歡迎程度，有時甚至在活動開始後兩小時內便銷售一空，吸引了許多來自縣外的遊客。會場內，箱裝和貨櫃裝的蘋果銷售一空，老顧客通常會一次購買好幾箱，分送給親戚和鄰居，這已成為慣例。現場陳列著套袋栽培的「富士蘋果」和沐浴陽光成長的「陽光富士蘋果」，能夠品嚐到兩種不同風味的蘋果，也是其魅力之一。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-14-00-0001', 'sheet_import', '体験する', '農業体験', NULL, 'りんご栽培の一年', '春の開花から冬の剪定まで、りんごづくりには多様な作業があります。', 'りんご栽培は春の受粉から始まり、夏には摘果で果実を選び抜きます。収穫期が近づくと「葉摘」で日当たりを良くし、さらに「玉回し」で実を回して均一に色づけます。並行して、園地の草刈りといった地味ながら重要な作業も欠かせません。8月下旬には「つがる」、秋には「秋映」「シナノゴールド」、冬前には「ふじ」と多彩な品種が収穫期を迎えます。冬は翌年に備えた剪定の季節へと移り、一年を通じた営みが続きます。', 'Experience', 'Hands-on Farming', NULL, 'A Year in Apple Cultivation', 'From the delicate blossoms of spring to the meticulous pruning of winter, apple cultivation in Iizuna is a year-round endeavor involving a diverse array of tasks.', 'Apple cultivation begins with spring Pollination, followed by summer Thinning to select the finest fruits. As harvest season approaches, Leaf Removal ensures optimal sun exposure, and Fruit Rotation is performed to achieve uniform coloring. Concurrently, essential yet often overlooked tasks like Weeding the orchards are diligently carried out. A diverse range of varieties reaches their harvest peak: Tsugaru in late August, Akibae and Shinano Gold in autumn, and Fuji Apple before winter. Winter transitions into the season of Pruning, preparing the trees for the following year, thus completing the continuous cycle of cultivation.', '體驗', '農事體驗', NULL, '蘋果栽培的一年', '從春季開花到冬季修剪，蘋果種植包含多樣的作業。', '蘋果栽培始於春季的授粉，夏季則透過摘果來篩選果實。隨著採收期臨近，農民會進行「摘葉」以確保充足的日照，並透過「轉果」使果實均勻著色。同時，園區的除草等看似不起眼卻至關重要的工作也必不可少。8月下旬迎來「津輕 (Tsugaru)」蘋果的採收期，秋季有「秋映 (Akie)」和「信濃黃金 (Shinano Gold)」，入冬前則有「富士蘋果 (Fuji)」等多樣品種陸續成熟。冬季則進入為來年做準備的修剪季節，一年四季的農事活動循環不息。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/b431fc30-8d6a-013e-bcf4-0a58a9feac02/tanpopo-16.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-14-00-0002', 'sheet_import', '体験する', '農業体験', NULL, 'りんごの木オーナー制度', '管理を任せる安心型と、自分で育てる体験型。選べる楽しみがあります。', '「りんごの木オーナー制度」は、1本の木を契約し、自分だけの収穫を楽しめる仕組みです。専門農家に管理を任せ、秋に収穫だけを体験する安心プランのほか、自ら剪定や摘果など木の手入れに関わるプランも用意されています。収穫は11月初旬〜下旬で、不作の場合も町内のりんごで保証されるものもあります。家族や友人、学校行事にも活用でき、自然と向き合いながら育てた実を自分の手で収穫する喜びは格別です。', 'Experience', 'Hands-on Farming', NULL, 'Apple Tree Patronage Program', 'Choose between a worry-free plan where expert farmers manage your tree, or an engaging experiential plan where you participate in its care.', 'The Apple Tree Patronage system allows you to contract a single tree and enjoy your very own harvest. Beyond the secure plan where professional farmers handle the management and you simply experience the autumn harvest, there are also options to actively participate in tree care, such as Pruning and Thinning. Harvesting typically takes place from early to late November, with some plans offering a guarantee of apples from within the town even in the event of a poor harvest. This program can be enjoyed by family and friends, or even utilized for school events, offering the unique joy of harvesting fruits you''ve nurtured yourself, connecting with nature.', '體驗', '農事體驗', NULL, '蘋果樹認養制度', '可選擇委託管理型或親自培育體驗型，享受多重樂趣。', '「蘋果樹認養制度」是一種透過簽約認養一棵蘋果樹，享受專屬採收樂趣的機制。除了可選擇委託專業農民管理，秋季僅體驗採收的安心方案外，也提供親自參與修剪、摘果等樹木照護工作的方案。採收期約在11月初至下旬，即使收成不佳，部分方案也會以町內的蘋果作為保證。此制度適用於家庭、朋友或學校活動，親手採收與大自然共育的果實，其喜悅更是非同凡響。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/f28314f0-8f03-013e-4554-0a58a9feac02/photo-advanced.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-14-00-0003', 'sheet_import', '体験する', '農業体験', NULL, '信州いいづなりんご学校', '都市と農村をりんごでつなぐ、新しい農業体験のスタイル。', '2017年に始まった「信州いいづなりんご学校」は、りんごづくりを通じて地域と多様に関わる人を増やすことを目的とした体験型プログラムです。日帰りのオープンキャンパスから中級・上級へと段階的に学べる仕組みがあり、収穫や選果の体験、農家との交流などを通じて奥深い農業の魅力を体感できます。参加者同士がつながり、新たなコミュニティが生まれる場でもあり、農家の励みにもなっています。', 'Experience', 'Hands-on Farming', NULL, 'Iizuna Apple School', 'A novel agricultural experience that bridges urban and rural communities through the shared passion for apples.', 'Launched in 2017, the Iizuna Apple School is an Experiential program designed to foster diverse connections with the region through apple cultivation. It offers a structured learning path, from one-day open campus sessions to intermediate and advanced courses, allowing participants to delve into the profound appeal of agriculture through experiences like Harvesting, Sorting, and interacting with Farmers. It also serves as a platform for participants to connect, fostering new Communities and providing encouragement to the Farmers.', '體驗', '農事體驗', NULL, '信州飯綱蘋果學校', '以蘋果為媒介，連結都市與農村，開創農業體驗新模式。', '「信州飯綱蘋果學校」始於2017年，旨在透過蘋果種植，增加與地區多元互動的人口，是一項體驗型計畫。課程設計從一日遊的開放日，到中級、高級的循序漸進學習模式，參與者可透過採摘、選果體驗以及與農民交流，深入感受農業的魅力。這裡不僅是參與者相互連結、建立新社群的場域，也成為激勵農民持續耕耘的力量。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/1eecc120-8efd-013e-3c90-0a58a9feac02/ogp.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/ringogakkou/', NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/ringogakkou//', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-14-00-0019', 'sheet_import', '体験する', '農業体験', NULL, 'ワーキングホリデー', '観光ではなく就農を見据えた実践型プログラム。', 'ワーキングホリデーは、3泊4日で農家に入り込み、うち2日間は朝から夕方まで本格的に農作業を行うプログラムです。受入農家は参加者をお客様扱いせず、リアルな暮らしを体感できるのが特徴。昼食は農家が用意し、季節ごとの多様な作業に携われます。就農を目指す方の初めの一歩として位置づけられ、専門家との相談や里親研修へとつながる重要な制度です。また、農業の人手不足を補い、地域との関係人口を広げる取り組みでもあります。', 'Experience', 'Hands-on Farming', NULL, 'Working Holiday', 'A practical program focused on starting a farming career, rather than just tourism.', 'The Working Holiday is a 3-night, 4-day program where participants immerse themselves in a farm, engaging in serious farm work from morning to evening for two of those days. A key feature is that host farmers do not treat participants as mere guests, allowing them to experience real farm life. Lunch is provided by the farmer, and participants can engage in various seasonal tasks. It is positioned as the first step for those aiming to Start Farming, and is an important system that leads to consultations with experts and Agricultural Mentorship. Furthermore, it helps address the shortage of agricultural labor and is an initiative to expand the Relationship Population with the community.', '體驗', '農事體驗', NULL, '農業打工度假', '這是一個著眼於從事農業而非觀光的實踐型計畫。', '農業打工度假是一個為期四天三夜的計畫，參與者將深入農家，其中兩天從早到晚進行實質的農事工作。其特色在於，接待農家不會將參與者視為客人，而是讓他們親身體驗真實的農村生活。午餐由農家準備，參與者可以參與季節性的多樣化農事。此計畫被定位為有志從事農業者的第一步，並能進一步連結與專家的諮詢及農事導師研修，是一個重要的制度。此外，這也是一項旨在彌補農業人力不足，並擴大與地方關係人口的措施。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/f28314f0-8f03-013e-4554-0a58a9feac02/photo-advanced.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/313.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-15-15-0004', 'sheet_import', '体験する', '滞在', '飲食店', 'そば処 よこ亭', NULL, NULL, 'Experience', 'Where to Stay', 'Dining', NULL, NULL, NULL, '體驗', '深度停留', '美食餐廳', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.iizuna-yokotei.com/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-15-16-0005', 'sheet_import', '体験する', '滞在', '宿泊', '丸為旅館', NULL, NULL, 'Experience', 'Where to Stay', 'Accommodations', NULL, NULL, NULL, '體驗', '深度停留', '住宿指南', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://marutame-ryokan.com/', NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/marutame_ryokan/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-15-17-0006', 'sheet_import', '体験する', '滞在', '入浴', 'むれ温泉天狗の館', NULL, NULL, 'Experience', 'Where to Stay', 'Onsen & Baths', NULL, NULL, NULL, '體驗', '深度停留', '溫泉與入浴', NULL, NULL, NULL, 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/f2820a40-8f03-013e-4553-0a58a9feac02/20584cc3360165367_5.jpg', NULL, NULL, NULL, NULL, NULL, 'https://tengunoyakata.com/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-15-18-0007', 'sheet_import', '体験する', '滞在', 'フォトスポット', '道の両側を彩るりんごの景色', '四季折々に変化するりんご畑の道沿いは、訪れる人を魅了する撮影名所。', 'りんご畑は、季節ごとに異なる表情を見せる絶好のフォトスポットです。秋には枝いっぱいに赤く実るりんごが並木のように連なり、まるで絵画のような景観をつくり出します。春には白や淡いピンクのりんごの花が咲き誇り、北信五岳の残雪を背景に撮影すれば幻想的な一枚に。ウェディングフォトや旅行の記念撮影の舞台としても人気が高く、自然と農の営みが織りなす景色は、訪れた人の心に鮮やかに残ります。', 'Experience', 'Where to Stay', 'Photo Spots', 'Apple Scenery Adorning the Roadsides', 'The ever-changing apple orchards lining the roads offer captivating photo opportunities throughout the seasons.', 'Apple orchards are exceptional photo spots that showcase different expressions with each passing season. In autumn, branches laden with ripe red apples line the roads like an avenue, creating a picturesque landscape. In spring, white and pale pink apple blossoms burst forth, and when photographed against the backdrop of the remaining snow on the Hokushin Five Mountains, they create a fantastical scene. These scenic routes are highly popular as settings for wedding photos and travel souvenirs, with the interwoven beauty of nature and agricultural life leaving a vivid impression on the hearts of visitors.', '體驗', '深度停留', '攝影私房景點', '道路兩旁點綴的蘋果景緻', '四季更迭的蘋果園沿路風光，是吸引遊客的攝影名勝。', '蘋果園是展現季節不同風貌的絕佳攝影私房景點。秋季時，枝頭結實纍纍的紅蘋果如蘋果樹道般綿延，營造出如畫般的景觀。春季時，白色或淡粉色的蘋果花盛開，若以北信五嶽的殘雪為背景拍攝，將會是一幅夢幻般的畫面。作為婚紗攝影和旅行紀念照的拍攝地點也廣受歡迎，自然與農耕生活交織而成的景色，將鮮明地留在到訪者的心中。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-15-18-0008', 'sheet_import', '体験する', '滞在', 'フォトスポット', 'ニュートンりんご並木', '英国由来の品種が並ぶりんご並木は、異国情緒漂う人気の撮影スポット。', 'いいづなアップルミュージアムの敷地内には、英国王立園芸協会から寄贈された品種が植えられた「ニュートンりんご並木」があります。ブラムリーズ・シードリングやグラニー・スミスといった外国種が実る様子は、国内では珍しい光景です。特に、日本梨のような姿をしたエグレモント・ラセットは訪れる人を驚かせ、写真に収めたくなる存在。歴史ある逸話に彩られた並木道を歩けば、りんごを通じて世界とつながる瞬間を感じられるでしょう。', 'Experience', 'Where to Stay', 'Photo Spots', 'Newton''s Apple Tree Avenue', 'An apple tree avenue featuring British-origin varieties, Newton''s Apple Tree Avenue is a popular photo spot with an exotic charm.', 'Within the grounds of the Iizuna Apple Museum, you''ll find "Newton''s Apple Tree Avenue," planted with varieties donated by the Royal Horticultural Society. The sight of foreign varieties such as Bramley''s Seedling and Granny Smith bearing fruit is a rare spectacle in Japan. The Egremont Russet, in particular, with its pear-like appearance, surprises visitors and is a must-capture for photographers. Walking along this avenue, adorned with historical anecdotes, allows you to feel a moment of connection to the world through apples.', '體驗', '深度停留', '攝影私房景點', '牛頓蘋果樹道', '種植著英國品種的蘋果樹道，是充滿異國情調的熱門攝影私房景點。', '飯綱蘋果博物館園區內，種植著由英國皇家園藝學會捐贈的品種，形成「牛頓蘋果樹道」。布蘭利 (Bramley''s Seedling) 和史密斯奶奶 (Granny Smith) 等外國品種結果的景象，在日本國內實屬罕見。特別是外形酷似日本梨的埃格雷蒙特褐鏽 (Egremont Russet)，更是令人驚訝，讓人忍不住想拍照留念。漫步於充滿歷史軼事的蘋果樹道，您將能感受到透過蘋果與世界連結的瞬間。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/f28334d0-8f03-013e-e63c-0a58a9feac02/IMG_0042_1_.jpeg', NULL, NULL, NULL, NULL, NULL, 'https://1127.info/sightseeing/5670/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-15-18-0009', 'sheet_import', '体験する', '滞在', 'フォトスポット', 'りんごのカーブミラー', '町の道端に現れる、りんごの縁取りが施されたユニークなカーブミラー。', 'りんごのカーブミラーは、赤い果実をかたどった縁取りが特徴のユニークな存在です。倉井地区の県道505号沿いでは農産物直売所近くに二面タイプが並び、芋川地区の県道60号沿いでも神社そばに設置。さらに柳里・古町地区の県道37号では、坂道に3基連続して並び、山並みを背景にした写真映えスポットとなっています。アップルミュージアム内でも展示が見られ、探索の楽しみを広げています。', 'Experience', 'Where to Stay', 'Photo Spots', 'Apple-Framed Curve Mirrors', 'Unique curve mirrors adorned with apple-shaped frames appear along the town''s roadsides.', 'The apple-framed Curve Mirrors are distinctive features characterized by their red, fruit-shaped borders. Along Prefectural Road 505 in the Kurai district, two-sided mirrors are positioned near a Farm Stand, while in the Imogawa district, they are installed near a shrine along Prefectural Road 60. Furthermore, on Prefectural Road 37 in the Yanagisato-Furumachi district, three mirrors are consecutively arranged on a Slope, creating a photo spot with the mountain ranges as a backdrop. Exhibitions of these mirrors can also be found within the Iizuna Apple Museum, enhancing the joy of exploration.', '體驗', '深度停留', '攝影私房景點', '蘋果彎道反射鏡', '出現在町內路邊，鑲有蘋果邊框的獨特彎道反射鏡。', '蘋果彎道反射鏡的特色是其以紅色果實為造型的邊框，獨具一格。在倉井地區的縣道505號沿線，農產物直銷所附近並排著兩面式反射鏡；在芋川地區的縣道60號沿線，神社旁也設有反射鏡。此外，在柳里・古町地區的縣道37號，坡道上連續設置了三座，成為以山脈為背景的熱門攝影景點。飯綱蘋果博物館內也有展示，增添了探索的樂趣。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/a0689660-8f74-013e-e468-0a58a9feac02/1203215052_61aa12acc7a20.jpg', NULL, NULL, NULL, NULL, NULL, 'https://mitsudon-marche.jp/blogs/blog/2023029?srsltid=AfmBOorw1wkSXtymzkq8eUFH94fkafmwhkEUGnC1DQf4dVUqRNheFAeP', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-00-0010', 'sheet_import', '体験する', 'アクセス', NULL, '車でお越しの場合', '首都圏から約3時間、長野市にも近い', '飯綱町は長野市に隣接しており、市街地から車で20〜30分で到着できます。町内移動は基本的に車が必須ですが、日常生活の利便性と豊かな自然環境を両立できる地域です。東京からは関越自動車道と上信越自動車道を経由し、信州中野ICから国道18号を通って約3時間でアクセス可能です。また、牟礼駅の駐車場を利用し、電車で長野市へ向かう方法もあり、車と公共交通機関を組み合わせた移動の自由度も魅力です。', 'Experience', 'Getting Around', NULL, 'Access by Car', 'Approximately 3 hours from the Tokyo Metropolitan Area, conveniently close to Nagano City.', 'Iizuna Town is adjacent to Nagano City, allowing for a comfortable 20-30 minute drive from the city center. While a car is generally essential for navigating within the town, Iizuna offers the unique advantage of balancing daily convenience with abundant natural surroundings. From Tokyo, you can reach Iizuna in about 3 hours by taking the Kan-etsu Expressway and Joshinetsu Expressway, then exiting at Shinshu-Nakano IC and continuing on National Route 18. Alternatively, you can utilize the parking facilities at Mure Station and take the train to Nagano City, providing the flexibility of combining car travel with public transportation.', '體驗', '交通指南', NULL, '駕車前往', '從首都圈約3小時車程，鄰近長野市', '飯綱町與長野市相鄰，從市區駕車約20至30分鐘即可抵達。町內移動基本上必須仰賴汽車，但這裡是一個能兼顧日常生活便利性與豐饒自然環境的地區。從東京出發，經由關越自動車道 (Kan-Etsu Expressway)和上信越自動車道 (Joshin-Etsu Expressway)，從信州中野交流道 (IC)沿著國道18號行駛，約3小時即可抵達。此外，您也可以利用牟禮站的停車場，轉乘電車前往長野市，結合汽車與大眾運輸工具的移動自由度也是一大魅力。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/866.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-00-0011', 'sheet_import', '体験する', 'アクセス', NULL, '電車でお越しの場合', '東京から電車で約2時間、牟礼駅が玄関口', '飯綱町を訪れる際、電車なら東京から約2時間でアクセス可能です。東京駅から北陸新幹線で長野駅へ、そこからしなの鉄道北しなの線に乗り換えると牟礼駅に到着します。町内の玄関口である牟礼駅は駐車場もあり、車を停めて電車に乗り換える利用者も多くいます。牟礼駅から長野市中心部までは電車で約25分と快適で、観光や日常の移動にも便利な拠点となっています。', 'Experience', 'Getting Around', NULL, 'Access by Train', 'Approximately 2 hours from Tokyo by train, with Mure Station as your gateway.', 'When visiting Iizuna Town by train, you can reach us from Tokyo in about 2 hours. Take the Hokuriku Shinkansen from Tokyo Station to Nagano Station, then transfer to the Shinano Railway Kita-Shinano Line, which will bring you to Mure Station. Mure Station, serving as the town''s primary gateway, offers parking, making it a popular choice for those who prefer to park their car and continue their journey by train. From Mure Station, it''s a comfortable 25-minute train ride to central Nagano City, establishing it as a convenient base for both sightseeing and daily commutes.', '體驗', '交通指南', NULL, '搭乘電車前往', '從東京搭乘電車約2小時，牟禮站是主要門戶', '造訪飯綱町時，搭乘電車從東京出發約2小時即可抵達。從東京車站搭乘北陸新幹線 (Hokuriku Shinkansen)至長野車站，再轉乘信濃鐵道北信濃線 (Shinano Railway Kita-Shinano Line)即可抵達牟禮站。作為町內主要門戶的牟禮站設有停車場，許多旅客會在此停車後轉乘電車。從牟禮站搭乘電車前往長野市中心約25分鐘，車程舒適，是觀光和日常移動的便利據點。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/866.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-00-0018', 'sheet_import', '体験する', 'アクセス', NULL, '電動自転車', 'Eバイクの貸出あり。坂道もスイスイ、里山サイクリング。', '牟礼駅降りてすぐ。飯綱町観光協会ではEバイク4台（クロス2・カゴ付2）を貸出しており、短距離の寄り道観光に好適。事前の電話予約と身分証の持参を。
※運行ダイヤ・料金・休止情報は変更される場合があります。お出かけ前に最新情報をご確認ください。', 'Experience', 'Getting Around', NULL, 'E-bike', 'E-bike rentals available. Effortless uphill rides for Satoyama Cycling.', 'Located right outside Mure Station, the Iizuna Town Tourism Association offers 4 E-bikes for rent (2 cross-bikes, 2 with baskets), ideal for short sightseeing detours. Advance phone reservations and presentation of identification are required. *Operating schedules, fees, and suspension information are subject to change. Please confirm the latest information before your trip.', '體驗', '交通指南', NULL, '電動自行車', '提供電動自行車租借服務。輕鬆征服坡道，暢遊里山單車旅行。', '從牟禮站出站後即可抵達。飯綱町觀光協會提供4輛電動自行車（2輛越野款、2輛附菜籃款）租借服務，非常適合短程順道觀光。請務必事先電話預約並攜帶身份證明文件。
※營運班次、費用、暫停服務資訊可能有所變更。出發前請務必確認最新資訊。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-20-0012', 'sheet_import', '体験する', 'アクセス', '町内での移動', 'iバス（定時定路線）', '平日運行。主要エリアを定時ダイヤで巡回。', '町内の主要拠点を結ぶ地域内バス。運賃は大人1乗車200円（小児100円）、ICカード「KURURU」利用可。飯綱温泉線・地蔵久保線・東柏原線の3系統で、平日（月〜金）のみ運行（土日祝・12/29〜1/3は運休）。通院や買い物など日常移動の基幹として使いやすい。路線図・時刻表は運行事業者のページで確認し、乗り継ぎ時間は余裕を持って計画を。
※運行ダイヤ・料金・休止情報は変更される場合があります。お出かけ前に最新情報をご確認ください。', 'Experience', 'Getting Around', 'Local Transport', 'i-Bus (Fixed Route & Schedule)', 'Operates on weekdays, circulating key areas on a fixed schedule.', 'The i-Bus is a local bus service connecting major hubs within Iizuna Town. The fare is 200 yen for adults (100 yen for children) per ride, and the IC card ''KURURU'' is accepted. It operates on three routes: the Iizuna Onsen Line, Jizokubo Line, and Higashi-Kashiwabara Line. The i-Bus runs only on weekdays (Monday-Friday) and is suspended on weekends, national holidays, and from December 29th to January 3rd. It serves as a convenient and essential mode of transport for daily activities such as hospital visits and shopping. Please check the route map and timetable on the operating company''s website and plan your transfers with ample time. Please note: Schedules, fares, and suspension information are subject to change. Kindly check the latest information before your trip.', '體驗', '交通指南', '町內交通方式', 'i巴士 (固定班次、固定路線)', '平日營運。依固定時刻表巡迴主要區域。', '連結町內主要據點的區域內巴士。車資為成人單趟200日圓（兒童100日圓），可使用IC卡「KURURU」。共有飯綱溫泉線、地藏久保線、東柏原線3條路線，僅限平日（週一至週五）營運（週六、週日、國定假日及12/29至1/3停駛）。作為就醫、購物等日常移動的主要交通工具，使用便利。請至營運業者網站確認路線圖與時刻表，並預留充裕的轉乘時間。
※營運班次、費用、停駛資訊可能有所變更。出發前請務必確認最新資訊。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.nagadenbus.co.jp/community/2021/09/iizuna-i.php', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-20-0013', 'sheet_import', '体験する', 'アクセス', '町内での移動', 'iバス（デマンドワゴン）', '事前予約で近くに来てくれる乗合交通。', '平日日中に運行する予約型の乗合ワゴン。利用登録（無料）後、受付センターへ電話予約で配車される。運賃は大人200円（小児100円）。「まち行き便」3便・「お帰り便」4便に合わせて運行し、役場・駅・病院・商店などへ直行できる。受付は平日8:00〜15:30、電話026-253-1128。夜間には牟礼駅前19:10頃発の「予約型ナイトワゴン」も設定（別途運行者へ予約）。
※運行ダイヤ・料金・休止情報は変更される場合があります。お出かけ前に最新情報をご確認ください。', 'Experience', 'Getting Around', 'Local Transport', 'i-Bus (On-demand Wagon)', 'A shared ride service available by advance reservation, picking you up nearby.', 'This reservation-based On-demand Wagon operates on weekdays during the daytime. After completing free user registration, you can request a Dispatch by calling the reception center. The Fare is 200 yen for adults (100 yen for children). It runs in coordination with 3 "Town-bound" services and 4 "Return" services, offering direct access to the town hall, station, hospitals, and shops. Reception is open weekdays from 8:00 AM to 3:30 PM; call 026-253-1128. A "reservation-based night wagon" is also available, departing from Mure Station around 7:10 PM (requires separate booking with the operator).
*Please note that the Schedule, Fares, and suspension information are subject to change. Please check the latest information before your trip.', '體驗', '交通指南', '町內交通方式', 'i巴士 (預約式共乘計程車)', '事先預約，隨叫隨到的共乘交通工具。', '平日白天營運的預約式共乘計程車。免費完成使用登記後，可致電服務中心預約叫車。車資為成人200日圓（兒童100日圓）。配合「前往市區班次」3班與「回程班次」4班營運，可直達町公所、車站、醫院、商店等地。服務時間為平日8:00至15:30，電話026-253-1128。夜間另設有從牟禮站前約19:10發車的「預約式夜間共乘計程車」（需另向營運業者預約）。
※營運班次、車資、停駛資訊可能變更。請於出發前確認最新資訊。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/traffic/i-bus/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-20-0014', 'sheet_import', '体験する', 'アクセス', '町内での移動', 'iバスコネクト（地域拠点バス）', '土日祝に運行、駅と観光エリアをつなぐ定時便。', '駅と観光・地域拠点をダイレクトに結ぶ定時路線。運賃は大人200円、小学生100円（未就学は無料）。IC「KURURU」や「IIZUNAであるきバスカード」も利用できる。運行日は土・日・祝で、冬季（12〜3月）は運休。季節イベントや週末観光にあわせやすいダイヤのため、平日の定時便・デマンド便と使い分けると移動計画が立てやすい。最新の時刻表は運行ページで確認を。
※運行ダイヤ・料金・休止情報は変更される場合があります。お出かけ前に最新情報をご確認ください。', 'Experience', 'Getting Around', 'Local Transport', 'i-Bus Connect (Community Hub Bus)', 'A scheduled service operating on weekends and holidays, connecting the station and tourist areas.', 'This scheduled route directly links the station with tourist and Community hubs. The Fare is 200 yen for adults and 100 yen for elementary school children (preschoolers ride free). IC "KURURU" (compatible with major IC cards like Suica) and "IIZUNAであるきバスカード" can also be used. It operates on Saturdays, Sundays, and national holidays, but is suspended during Winter (December to March). The Timetable is designed to align with seasonal events and weekend tourism, making it easy to plan your travel when used in conjunction with weekday scheduled and On-demand Wagon services. Please check the latest Timetable on the operating page.
*Please note that the Schedule, Fares, and suspension information are subject to change. Please check the latest information before your trip.', '體驗', '交通指南', '町內交通方式', 'i巴士Connect (地區據點巴士)', '週末及例假日行駛，連結車站與觀光區域的定時班次。', '連結車站與觀光、地區據點的定時路線。車資為成人200日圓，小學生100日圓（學齡前兒童免費）。亦可使用IC卡「KURURU」及「IIZUNAであるきバスカード」。營運日為週六、週日及例假日，冬季（12月至3月）停駛。由於營運班次配合季節活動及週末觀光，若能與平日的定時班次、預約式共乘計程車搭配使用，將更容易規劃行程。最新時刻表請至營運頁面確認。
※營運班次、車資、停駛資訊可能變更。請於出發前確認最新資訊。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/4190.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-20-0015', 'sheet_import', '体験する', 'アクセス', '町内での移動', 'タクシー', '台数に限りあり。配車は事前予約が安心・確実。', '町内の主な事業者は「有限会社飯綱ハイヤー」（TEL 026-253-7474）など。地域特性上、保有台数が少なく即時配車は難しい状況が多い。早朝・夜間・天候悪化時は特に混み合うため、到着時刻から逆算して予約を。駅到着後の流し期待より、列車の発着時刻に合わせて迎車を手配するのがおすすめ。運賃・支払い方法・ジャンボ車両の可否などは事前に確認を。
※運行ダイヤ・料金・休止情報は変更される場合があります。お出かけ前に最新情報をご確認ください。', 'Experience', 'Getting Around', 'Local Transport', 'Taxi', 'Limited number of taxis. Advance booking ensures reliable Dispatch.', 'The main operator in town is Iizuna Hire Co., Ltd. (TEL 026-253-7474). Due to the regional characteristics, the number of taxis available is limited, making immediate Dispatch often difficult. It tends to be particularly busy during early mornings, evenings, and in bad weather, so it is recommended to book in advance, calculating backward from your desired arrival time. Instead of hoping to hail a taxi upon arrival at the station, it is advisable to arrange a Taxi Pickup Service in accordance with train arrival and departure times. Please confirm Fares, payment methods, and availability of larger vehicles in advance.
*Please note that the Schedule, Fares, and suspension information are subject to change. Please check the latest information before your trip.', '體驗', '交通指南', '町內交通方式', '計程車', '數量有限。建議事先預約，安心又可靠。', '町內主要業者為「有限会社飯綱ハイヤー」（電話026-253-7474）等。 由於地區特性，計程車數量較少，即時叫車通常較為困難。 清晨、夜間或天氣惡劣時尤其容易客滿，建議從抵達時間倒推預約。與其期待抵達車站後隨機叫車，不如配合列車發車及抵達時刻預約接送服務更為推薦。請事先確認車資、支付方式及是否提供大型計程車等資訊。
※營運班次、車資、停駛資訊可能變更。請於出發前確認最新資訊。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/traffic/taxi/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-20-0016', 'sheet_import', '体験する', 'アクセス', '町内での移動', 'レンタカー', '無人手続きで短時間から手配可。LINE予約・事前決済でスムーズ。', '地域発の「いいづなレンタカー」では、LINEで24時間予約受付・事前決済に対応。代表的な料金は日帰りパック4,800円（レンタカー3,300円＋任意保険1,500円）、1泊2日8,500円、2泊3日13,300円、1週間21,500円など（返却は各プランの20時まで）。荷物が多い旅程や周辺エリアの周遊に便利。車両情報・受け渡し方法は公式サイトで最新案内を確認。
※運行ダイヤ・料金・休止情報は変更される場合があります。お出かけ前に最新情報をご確認ください。', 'Experience', 'Getting Around', 'Local Transport', 'Rent-a-car', 'Unmanned procedures for short-term rentals. Smooth booking and pre-payment via LINE.', 'Iizuna Rent-a-car, a local service, offers 24-hour booking and pre-payment via LINE. Typical rates include a 4,800 yen day trip package (3,300 yen for the rental car + 1,500 yen for optional insurance), 8,500 yen for a 2-day/1-night plan, 13,300 yen for a 3-day/2-night plan, and 21,500 yen for a week (returns by 8 PM for all plans). This service is convenient for itineraries with a lot of luggage or for exploring the surrounding areas. Please check the official website for the latest information on vehicle details and pick-up/return methods. *Operating schedules, fees, and suspension information are subject to change. Please confirm the latest information before your trip.', '體驗', '交通指南', '町內交通方式', '租車服務', '無人化手續，可短時間租用。透過LINE預約與事前支付，流程更順暢。', '由當地營運的「飯綱租車」提供24小時LINE預約與事前支付服務。主要費用方案包括：當日來回方案4,800日圓（租車費3,300日圓＋任意保險1,500日圓）、一泊二日8,500日圓、二泊三日13,300日圓、一週21,500日圓等（所有方案皆須於當日20:00前歸還）。此服務非常適合行李較多的行程，或欲周遊周邊地區的旅客。車輛資訊與取還車方式請參考官方網站的最新公告。
※營運班次、費用、暫停服務資訊可能有所變更。出發前請務必確認最新資訊。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://iizuna-rent-a-car.com/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('14-19-20-0017', 'sheet_import', '体験する', 'アクセス', '町内での移動', 'よるタク', '夜間の駅発着後をサポート、町内移動を半額料金で提供。', '令和7年3月11日から、牟礼駅を拠点とした夜間の移動を支援する実証運行「よるタク」が始まりました。運行日は毎週火曜〜土曜、19:30から終電到着時間＋移動を含め約23:00ごろまで。町内移動なら通常メーター料金の半額（上限2,000円）で利用可能です。町外への移動は通常メーター料金扱い。利用者は牟礼駅前での待機車利用や、指定場所への迎車を申請でき、どなたでも利用可能です。運行は豊野タクシーが担当。期間は実証運行として、利用状況に応じて見直しされる予定です。', 'Experience', 'Getting Around', 'Local Transport', 'Yorutaku', 'Supporting night-time travel from/to the station, offering town-internal transportation at half price.', 'From March 11, 2025, the trial operation of "Yorutaku" began, supporting night-time travel centered around Mure Station. It operates every Tuesday to Saturday, from 7:30 PM until approximately 11:00 PM, including travel time after the last train arrives. For travel within the town, you can use the service at half the regular meter fare (up to 2,000 yen). Travel outside the town is charged at the regular meter fare. Users can request a waiting taxi at Mure Station or a Taxi Pickup Service to a specified location, and anyone can use the service. Toyono Taxi is responsible for the operation. As a trial operation, the service will be reviewed based on usage.', '體驗', '交通指南', '町內交通方式', '夜間計程車服務', '支援夜間從車站出發或抵達的移動需求，町內移動享半價優惠。', '自令和7年3月11日起，以牟禮站為據點，支援夜間移動的試營運「夜間計程車」服務正式啟動。營運日期為每週二至週六，時間從19:30開始，直至末班車抵達時間加上移動時間，約至23:00左右。若在町內移動，可享通常跳錶費用半價優惠（上限2,000日圓）。若移動至町外，則按通常跳錶費用計算。使用者可選擇在牟禮站前搭乘待命車輛，或申請至指定地點接送，任何人皆可利用。此服務由豐野計程車負責營運。作為試營運期間，將根據使用狀況進行重新評估。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/11711.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-21-00-0001', 'sheet_import', '暮らす', '就労', NULL, 'いいコネワークス', '複数の事業者をつなぎ、多彩な仕事に関わる新しい仕組みです。', '協同組合いいコネワークスは、国の「特定地域づくり協同組合制度」を活用して設立されました。町内の複数の事業者が連携し、組合員となるワーカーを共同で受け入れる仕組みを整えています。仕事内容は農作業や観光施設の運営補助、地元企業の事務やサービス業など幅広く、季節や個人の希望に応じて組み合わせが可能です。ひとつの職場に縛られず複数の仕事を担うことで、収入と暮らしの安定を図りながら、地域の多様な担い手として活躍できるのが大きな特徴です。', 'Lifestyle', 'Work Opportunities', NULL, 'Ii-Cone Works', 'A new system connecting multiple businesses and offering diverse work opportunities.', 'The Ii-Cone Works Cooperative was established utilizing the national "Designated Regional Development Cooperative System." This framework enables multiple businesses within the town to collaborate and jointly employ workers who become cooperative members. The scope of work is broad, encompassing agricultural tasks, support for tourism facility operations, administrative roles for local companies, and service industry positions. These roles can be combined according to seasonal needs and individual preferences. A key feature is the ability for workers to engage in multiple jobs without being tied to a single workplace, thereby stabilizing income and livelihood while contributing as diverse human resources to the community.', '生活', '在地就業', NULL, 'Ii-Cone Works', '這是一個連結多個事業體，參與多元工作的新機制。', 'Ii-Cone Works合作社是活用日本政府「特定地域營造事業合作社制度」所設立的。它建立了一個由町內多個事業體合作，共同接納組合員工作者的機制。工作內容廣泛，包含農事工作、觀光設施營運協助、當地企業的行政事務及服務業等，可依季節或個人意願彈性組合。其最大特色在於，工作者不被單一職場束縛，可從事多種工作，在確保收入與生活穩定的同時，作為地區多元的貢獻者活躍。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/ae7227a0-8f30-013e-1d10-0a58a9feac02/_______________1.png', NULL, NULL, NULL, NULL, NULL, 'https://iicone-works.com//', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-21-00-0002', 'sheet_import', '暮らす', '就労', NULL, '地域おこし協力隊', '多様な人材が地域に飛び込み、就労や移住の形を切り拓いています。', '地域おこし協力隊制度は、外部人材の力を地域づくりに活かす仕組みです。活動分野は移住促進や情報発信、農業支援、観光対策、空き家活用など多岐にわたり、隊員のスキルや希望に合わせて柔軟に設定されています。任期を通じて住民や農家と関わりを深め、定住や起業へとつなげる事例も多くあります。一方で、地域社会の濃密さや税金で賄われる活動への責任感など「リアル」な課題も存在します。制度を通じ、就労の機会と地域への新しい関わり方が広がっています。', 'Lifestyle', 'Work Opportunities', NULL, 'Local Vitalization Cooperator', 'Diverse individuals are pioneering new forms of employment and relocation within the community.', 'The Local Vitalization Cooperator program is a system designed to leverage external talent for community building. Activity areas are diverse, including relocation promotion, information dissemination, agricultural support, tourism initiatives, and the utilization of vacant houses, all flexibly tailored to the skills and aspirations of the cooperators. Many instances show cooperators deepening their ties with residents and farmers throughout their tenure, leading to permanent settlement or the establishment of new businesses. However, there are also "real" challenges, such as the close-knit nature of local society and the sense of responsibility for activities funded by taxes. Through this program, opportunities for employment and new ways of engaging with the community are expanding.', '生活', '在地就業', NULL, '地方創生協力隊', '多元人才投入地方，開拓了就業與移居的新模式。', '地方創生協力隊制度是活用外部人才力量，推動社區營造的機制。活動領域多元，涵蓋移居促進、資訊傳播、農業支援、觀光對策、空屋活化等，並根據隊員的技能與意願彈性設定。許多案例顯示，隊員在任期內與居民和農民建立深厚關係，成功轉為定居或創業。同時，也存在著地區社會的緊密性、以及對由稅金支應的活動所應負責任感等「真實」的課題。透過此制度，就業機會與參與地區事務的新方式正不斷擴展。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/11283.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-21-00-0003', 'sheet_import', '暮らす', '就労', NULL, '一般求人相談', '町内外での仕事探しを支援する、信頼できる相談窓口をご紹介します。', '求人や就職に関する相談は、町内の「飯綱町無料職業紹介所」が中心となって対応しています。役場第2庁舎の窓口で、平日8時30分から17時15分まで受け付けており、求人情報の提供や雇用のあっせんを行っています。さらに、広域の求人を対象とする「ハローワーク長野」でも相談可能です。農業や福祉分野をはじめ、地域の特色に根ざした求人を見つけたい方や移住希望者にとって、これらの窓口は心強いサポートとなっています。', 'Lifestyle', 'Work Opportunities', NULL, 'General Job Consultation', 'Introducing reliable consultation services to support job searching both within and outside the town.', 'For consultations regarding job openings and employment, the Iizuna Town Job Placement Office, located within the town, serves as the primary point of contact. The office, situated at the Town Hall Annex 2, is open on weekdays from 8:30 AM to 5:15 PM, providing job information and employment mediation. Additionally, consultations are available at Hello Work Nagano, which covers a wider range of job opportunities. For those seeking jobs rooted in local characteristics, particularly in agriculture and welfare, and for individuals considering relocation, these consultation services offer invaluable support.', '生活', '在地就業', NULL, '一般徵才諮詢', '為您介紹支援町內外求職的可靠諮詢窗口。', '關於徵才與就業的諮詢，主要由町內的「飯綱町免費職業介紹所」負責。該窗口位於町公所第二辦公大樓，平日上午8點30分至下午5點15分受理，提供徵才資訊並協助就業。此外，針對廣域職缺，也可向「公共職業安定所長野」諮詢。對於希望尋找以農業和福利領域為首，植根於地區特色的職缺，以及對於移居者而言，這些窗口都是強而有力的支援。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/306.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-22-00-0004', 'sheet_import', '暮らす', '移住', NULL, '移住定住支援サイト', '住まい・仕事・子育て・補助金情報を一元化。物件検索やオンライン相談まで、このサイトで完結。', '公式の移住定住支援サイトでは、売買・賃貸・町営住宅・土地情報の閲覧に加え、移住者インタビューやコラムで暮らしの実像を把握できます。オンライン相談窓口も設置。支援制度は、中古住宅等購入に最大50万円、家賃助成は最長3年で最大48万円、空き家片付けは最大20万円を補助。奨学金返還は10年で最大200万円、結婚新生活や福祉施設従事者向け支援も案内されています。まずはサイトの「住む／働く／子育て／相談」各ページをチェック。', 'Lifestyle', 'Settling In', NULL, 'Official Relocation and Settlement Support Website', 'Your comprehensive guide to housing, employment, childcare, and subsidies in Iizuna Town. Everything you need, from property searches to online consultations, is available here.', 'The official Relocation and Settlement Support Website offers access to information on properties for sale, rentals, town-managed housing, and land. You can also gain a realistic understanding of daily life through interviews with current residents and insightful columns. An Online Consultation service is also available. Financial support programs include up to 500,000 yen for purchasing pre-owned homes, a Rent Subsidy of up to 480,000 yen over a maximum of three years, and up to 200,000 yen for Vacant House cleanup. Additionally, support for Scholarship Repayment (up to 2,000,000 yen over 10 years), Newlywed Life Support, and assistance for welfare facility workers are also detailed. Begin your journey by exploring the ''Living,'' ''Working,'' ''Childcare,'' and ''Consultation'' pages on the website.', '生活', '移居支援', NULL, '移居定居支援網站', '整合居住、工作、育兒及補助金資訊。從物件搜尋到線上諮詢，一站式完成所有需求。', '官方移居定居支援網站不僅提供買賣、租賃、町營住宅及土地資訊的瀏覽，您還可以透過移居者訪談和專欄，掌握當地生活的真實面貌。網站也設有線上諮詢窗口。支援制度包括：購買中古住宅等最高補助50萬日圓；租金補助最長3年，最高48萬日圓；空屋整理最高補助20萬日圓。獎學金還款支援10年內最高200萬日圓，同時也提供結婚新生活支援及福利設施從業人員支援。請務必先查看網站的「居住／工作／育兒／諮詢」各頁面。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/fc5f32a0-8f2f-013e-1cfe-0a58a9feac02/ijuportal.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/ijuportal/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-22-00-0005', 'sheet_import', '暮らす', '移住', NULL, '移住体験住宅', '古民家に最長6泊7日滞在。生活導線や買い物距離まで体感できるお試し住宅。', '古民家を1組で最長6泊7日まで利用可能。使用料は無料（清掃料1回1,000円、寝具レンタルは1組1日1,000円）。チェックイン15:00–17:00／チェックアウト8:30–10:00。自炊可・Wi-Fi対応、風呂・洗濯機・電子レンジ等を備える。最寄のしなの鉄道・牟礼駅まで約4.6km、日帰り温泉は約3.7km、役場は約3.5km。利用前に移住相談と申請書提出が必須。運営・申込窓口は株式会社カンマッセいいづな（平日8:30–17:15）。移動は車が基本。', 'Lifestyle', 'Settling In', NULL, 'Relocation Experience Housing', 'Stay in a Traditional Japanese House for up to 6 nights and 7 days. This Trial Housing allows you to experience the flow of daily life and proximity to shopping.', 'A Traditional Japanese House is available for one group for up to 6 nights and 7 days. Usage is free (cleaning fee: 1,000 yen per stay, bedding rental: 1,000 yen per set per day). Check-in is from 3:00 PM to 5:00 PM, and check-out is from 8:30 AM to 10:00 AM. The house is equipped for self-catering, offers Wi-Fi, and includes a bath, washing machine, and microwave. The nearest Shinano Railway Mure Station is approximately 4.6 km away, a day-trip hot spring is about 3.7 km, and the town hall is around 3.5 km. Prior Relocation Consultation and submission of an application form are required before use. The facility is managed and applications are handled by Commase Iizuna Co., Ltd. (weekdays 8:30 AM to 5:15 PM). Transportation by car is generally recommended.', '生活', '移居支援', NULL, '移居體驗住宅', '最長可停留6晚7天的古民家。親身體驗生活動線與購物便利性的試住方案。', '每組家庭最長可利用古民家6晚7天。使用費免費（清潔費每次1,000日圓，寢具租借每組每天1,000日圓）。入住時間15:00–17:00／退房時間8:30–10:00。可自炊、支援Wi-Fi，並備有浴室、洗衣機、微波爐等設備。距離最近的信濃鐵道・牟禮站約4.6公里，當日往返溫泉約3.7公里，町公所約3.5公里。使用前必須進行移居諮詢並提交申請書。營運・申請窗口為株式会社カンマッセいいづな（平日8:30–17:15）。移動方式以汽車為主。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/fc5f1150-8f2f-013e-1cfd-0a58a9feac02/iizuna-house-4.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/docs/892.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-22-00-0006', 'sheet_import', '暮らす', '移住', NULL, '移住相談窓口', '平日役場窓口相談に加え、予約制オンライン相談も可能。', '相談は「役場 企画課 人口増推進室」で随時受付。窓口は平日8:30〜17:15、電話は026-253-2511。オンライン相談は毎日（12/28〜1/3除く）、10:00〜19:00の開始枠で1回30分。予約は希望日の1週間前までにフォームから申し込み可能。メール問い合わせ（jinko@town.iizuna.nagano.jp）も対応。あわせて、出張移住相談会や移住体験ツアーの開催情報も案内される。', 'Lifestyle', 'Settling In', NULL, 'Relocation Consultation Desk', 'In addition to in-person consultations at the Town Hall on weekdays, scheduled Online Consultation is also available.', 'Consultations are accepted at the Town Hall, Planning Division, Population Growth Promotion Office during regular business hours: weekdays from 8:30 AM to 5:15 PM. You can also call at 026-253-2511. Online Consultation is available daily (except December 28th to January 3rd), with 30-minute slots starting between 10:00 AM and 7:00 PM. Reservations can be made via the online form up to one week in advance of your desired date. Email inquiries are also welcome at jinko@town.iizuna.nagano.jp. Information on upcoming on-site Relocation Consultation events and Relocation Experience Tours is also provided.', '生活', '移居支援', NULL, '移居諮詢窗口', '除平日町公所窗口諮詢外，亦提供預約制線上諮詢服務。', '諮詢可隨時在「町公所 企劃課 人口增加推進室」辦理。窗口服務時間為平日8:30〜17:15，電話號碼為026-253-2511。線上諮詢服務每日開放（12/28〜1/3除外），開始時段為10:00〜19:00，每次30分鐘。預約可於希望日期的一週前透過表單申請。也接受電子郵件諮詢（jinko@town.iizuna.nagano.jp）。同時也提供巡迴移居諮詢會及移居體驗之旅的舉辦資訊。', 'https://s3-ap-northeast-1.amazonaws.com/s3.peraichi.com/userData/cadd36d5-015f-4440-aa3c-b426c32c22a0/img/fc5c4ba0-8f2f-013e-1cfc-0a58a9feac02/img-soudan-01.jpg', NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/ijuportal/support/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-23-00-0007', 'sheet_import', '暮らす', '就農', NULL, '新規就農里親制度', '長期研修で基礎から独立まで伴走。概ね3年の道のりを、里親の実地指導と地域の支援で確実に。', '制度の流れは、①事前相談（研修開始の約半年前まで）で作目・研修先・支援制度を決定。窓口は産業観光課農政係や長野農業農村支援センター。②前基礎研修約1年。③里親研修1〜2年で実地習得と農地確保、就農計画づくり。④独立。研修期間中の定住を推奨し、地域連携や農地紹介につながる。毎月の無料農地相談も活用可。目安は相談開始から独立まで約3年で、実践力と地域ネットワークを同時に育む。', 'Lifestyle', 'Start Farming', NULL, 'New Farmer Mentorship Program', 'A long-term training program that guides aspiring farmers from foundational knowledge to independent operation. This approximately three-year journey is solidified by hands-on guidance from experienced mentors and robust community support.', 'The program unfolds in four key stages: (1) **Pre-consultation** (up to approximately six months before training begins) to determine your chosen crops, training location, and available support systems. Contact points include the Industrial Tourism Division, Agricultural Policy Section and the Nagano Agriculture and Rural Support Center. (2) **Preliminary Basic Training** for about one year. (3) **Mentorship Program** for one to two years, focusing on practical skill acquisition, securing farmland, and developing your Farming Plan. (4) **Independence**. Settling In within the community during the training period is highly encouraged, as it fosters strong community collaboration and facilitates farmland introduction. You can also utilize the monthly Free Farmland Consultation. The entire process, from initial consultation to independent farming, typically spans about three years, allowing you to cultivate both practical skills and a robust local network.', '生活', '農業創業', NULL, '新進農民里親制度', '透過長期培訓，從基礎到獨立全程陪伴。約三年的歷程，在里親的實地指導與地區支援下，穩健前行。', '制度流程為：①事前諮詢（研修開始前約半年前）以確定作物種類、研修地點與支援制度。窗口為產業觀光課農政股及長野農業農村支援中心。②前期基礎培訓約1年。③里親培訓1至2年，進行實地學習、取得農地並制定務農計畫。④獨立。鼓勵研修期間定居，有助於建立地區連結與農地介紹。亦可利用每月免費農地諮詢服務。目標是從諮詢開始到獨立約3年，同時培養實踐能力與地區網絡。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/ijuportal/work/farming.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('21-23-00-0008', 'sheet_import', '暮らす', '就農', NULL, '就農相談窓口', '研修開始の半年前に動くのが成功の近道。相談先・支援内容・連絡先を紹介します。', '最初の相談から独立までの目安は約3年。主な窓口は産業観光課農政係（026-253-4765）と長野農業農村支援センター。研修先や活用補助の選定は、研修開始の半年前までに行うのが推奨です。就農コーディネーターが就農計画づくりを伴走し、毎月の無料農地相談で農地確保を支援。里親研修制度で地域の農家で学ぶことが推奨され、地域との関係づくりのため研修期間中の居住も勧められます。', 'Lifestyle', 'Start Farming', NULL, 'Farming Consultation Service', 'Taking action six months before your training begins is the shortcut to success. Here, we introduce key consultation points, support details, and contact information.', 'The journey from your initial consultation to independent farming typically takes about three years. The primary contact points are the Industrial Tourism Division, Agricultural Policy Section (026-253-4765) and the Nagano Agriculture and Rural Support Center. It is highly recommended to select your training location and support programs up to six months before your training commences. A dedicated Farming Coordinator will guide you in developing your Farming Plan, and monthly Free Farmland Consultation services are available to assist with securing farmland. Learning from experienced local farmers through the Mentorship Program is encouraged, and residing in the area during your training period is also recommended to foster strong community relationships.', '生活', '農業創業', NULL, '從事農業諮詢窗口', '在研修開始半年前採取行動是成功的捷徑。本文將介紹諮詢單位、支援內容與聯絡方式。', '從首次諮詢到獨立的預計時間約為3年。主要窗口為產業觀光課農政股（026-253-4765）及長野農業農村支援中心。建議在研修開始半年前完成研修地點與補助金的選擇。務農協調員將全程協助制定務農計畫，並透過每月免費農地諮詢協助取得農地。建議透過里親研修制度向當地農民學習，並鼓勵在研修期間居住於當地，以建立地區關係。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/ijuportal/work/farming.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('24-24-24-0001', 'sheet_import', '営む', '栽培支援', '講習会', 'JAながの飯綱りんご部会による講習会', '“やる気があれば誰でも作れ・稼げる”を掲げる、担い手不足と技術継承に応える通年プログラムです。', '就農5年目以内を主対象に、基礎から収益設計まで1年間で体系化。共有技術と品質基準による「飯綱モデル」を確立し、生産に専念できる稼げる仕組みを築く。2025年の初回は開花期の防除適期と低温障害をテーマに、JAながの技術員・営農部、長野県農業農村支援センター、部会役員が指導。圃場実習と質疑、受講生同士のコミュニティ形成、アンケートで内容改善を進め、次の指導者層の育成を目指す。', 'Business', 'Grower Support', 'Workshops', 'Training Seminar by JA Nagano Iizuna Apple Club', 'A year-round program addressing the shortage of successors and promoting Skills Succession, based on the principle that anyone with motivation can cultivate and earn a living.', 'Primarily targeting new farmers within their first five years of Start Farming, this program systematically covers everything from basic cultivation techniques to profit planning over one year. It establishes the ''Iizuna Model'' through shared techniques and quality standards, creating a profitable system that allows farmers to concentrate on production. The inaugural session in 2025 focused on optimal Pest Control during flowering and Frost Damage, with guidance from JA Nagano technical staff and agricultural department, the Nagano Prefectural Agricultural and Rural Support Center, and Iizuna Apple Club executives. Through field practicals, Q&A sessions, Community building among participants, and content improvement based on surveys, the program aims to foster the next generation of instructors.', '經營', '栽培支援', '技術講習會', 'JA長野飯綱蘋果社講習會', '秉持「只要有心，人人都能種植並獲利」的理念，旨在解決農業接班人不足與技術傳承問題的全年課程。', '主要針對從事農業5年以內的農民，在一年內系統化地教授從基礎知識到收益規劃。旨在確立以共享技術和品質標準為基礎的「飯綱模式」，建立能讓農民專注生產並獲利的機制。2025年的首次課程以開花期的病蟲害防治適期與低溫災害為主題，由JA長野技術人員、營農部、長野縣農業農村支援中心以及社團幹部進行指導。透過田間實習與問答、促進學員間的社群建立，並藉由問卷調查持續改進課程內容，旨在培養下一代的指導者。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://iizuna.jp/docs/12335.html', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('24-24-25-0002', 'sheet_import', '営む', '栽培支援', '補助金', '飯綱町農業振興対策事業補助金（振興果樹苗木導入事業）', '果樹農業の将来を見据えた苗木購入費を支援します。', '振興果樹苗木導入事業は、新たに果樹を植栽する農業者を対象に、苗木購入費の一部を補助する制度です。町内に住所を有する農業者が対象で、対象経費は新品苗木の購入費。上限額が設定されており、定められた補助率に基づき支援を受けられます。高齢化や資材高騰による農地の維持が課題となるなか、地域の農業を次世代につなぐための重要な取り組みです。', 'Business', 'Grower Support', 'Grants & Subsidies', 'Iizuna Town Agricultural Promotion Measures Subsidy (Promotional Fruit Sapling Introduction Project)', 'Supporting Sapling purchase costs for the future of fruit farming.', 'The Promotional Fruit Sapling Introduction Project is a system that subsidizes a portion of Sapling purchase costs for farmers newly planting fruit trees. It targets farmers residing in Iizuna Town, and eligible expenses include the purchase cost of new Saplings. A maximum amount is set, and support is provided based on a predetermined Subsidy rate. Amidst challenges in maintaining farmland due to an aging population and rising material costs, this is a crucial initiative to connect local agriculture to the next generation.', '經營', '栽培支援', '政府補助金', '飯綱町農業振興對策事業補助金（振興果樹苗木引進事業）', '著眼於果樹農業的未來，支援苗木購買費用。', '振興果樹苗木引進事業是一項以新植果樹的農民為對象，補助部分苗木購買費用的制度。對象為在町內設有住所的農民，補助對象費用為全新苗木的購買費。設有補助上限金額，可依據規定的補助比例獲得支援。在高齡化與資材價格飆漲導致農地維護成為課題之際，這是將地區農業傳承給下一代的重要措施。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/fs/8/0/3/6/8/_/__7___________.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('24-24-25-0003', 'sheet_import', '営む', '栽培支援', '補助金', '飯綱町元気な農業者育成事業補助金（大型農業用機械整備事業）', '認定農業者や新規就農者の機械導入を強力に支援。', '大型農業用機械整備事業は、認定農業者や認定新規就農者を対象に、大型農業機械や施設整備にかかる費用の一部を補助する制度です。新品の導入はもちろん、一部汎用性のある中古機械も対象となります。条件として一定規模以上の経営耕地面積や受益面積が求められます。農業の効率化と生産性向上を目的に、機械更新や省力化を進めるための大きな支えとなっています。', 'Business', 'Grower Support', 'Grants & Subsidies', 'Iizuna Town Energetic Farmer Development Project Subsidy (Large-scale Agricultural Machinery Maintenance Project)', 'Strongly supporting the introduction of machinery for certified farmers and New Farmers.', 'The Large-scale Agricultural Machinery Maintenance Project is a system that subsidizes a portion of the costs for large Agricultural Machinery and facility development for certified farmers and certified New Farmers. It covers not only the introduction of new equipment but also some versatile used machinery. Conditions include a certain scale of cultivated land area or beneficiary area. It serves as significant support for promoting machinery updates and Labor-saving, with the aim of improving agricultural Efficiency Optimization and productivity.', '經營', '栽培支援', '政府補助金', '飯綱町活力農民培育事業補助金（大型農業機械整備事業）', '強力支援認定農民與新進農民引進機械。', '大型農業機械整備事業是一項以認定農民及認定新進農民為對象，補助大型農業機械及設施整備部分費用的制度。不僅限於引進全新機械，部分具通用性的中古機械也包含在內。條件是需要達到一定規模以上的經營耕地面積或受益面積。以農業效率化與生產力提升為目的，是推動機械更新與省力化的重要支持。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/fs/8/0/3/6/8/_/__7___________.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('24-24-25-0004', 'sheet_import', '営む', '栽培支援', '補助金', '飯綱町共同利用農業機械導入事業補助金', '複数農家や団体が活用できる共同機械導入を補助します。', '共同利用農業機械導入事業補助金は、5戸以上で構成される団体や農業法人を対象に、農業機械導入費用を補助する制度です。新品機械の購入を基本としつつ、一部中古機械も対象に含まれます。条件として一定規模以上の受益面積が求められ、補助率や上限額が設けられています。地域の農家が機械を共同で利用することで、導入コストの削減や作業効率の向上につながり、持続可能な農業経営を後押しします。', 'Business', 'Grower Support', 'Grants & Subsidies', 'Iizuna Town Subsidy Program for Joint Agricultural Machinery Introduction', 'This program provides subsidies for the joint introduction of agricultural machinery, available to multiple farmers and organizations.', 'The Iizuna Town Subsidy Program for Joint Agricultural Machinery Introduction targets organizations comprising five or more farming households and agricultural corporations, offering financial assistance for the cost of introducing agricultural machinery. While primarily covering the purchase of new machinery, certain used equipment is also eligible. Conditions include a minimum beneficiary area of a specified size, and defined subsidy rates and maximum amounts are in place. By enabling local farmers to share machinery, this initiative helps reduce initial investment costs and improves operational efficiency, thereby fostering sustainable agricultural management.', '經營', '栽培支援', '政府補助金', '飯綱町共同利用農業機械引進事業補助金', '本補助金旨在協助多戶農家或團體共同引進農業機械。', '飯綱町共同利用農業機械引進事業補助金，是一項以由5戶以上農家組成的團體或農業法人為對象，補助農業機械引進費用的制度。原則上以購買全新機械為主，但部分中古機械也包含在補助範圍內。補助條件要求受益面積須達一定規模以上，並設有補助比例及上限金額。透過地區農家共同利用機械，有助於降低引進成本並提升作業效率，進而支持永續的農業經營。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.town.iizuna.nagano.jp/fs/8/0/3/6/8/_/__7___________.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
